import{_ as o,o as c,c as d,ae as l}from"./chunks/framework.B1ddJaIi.js";const _=JSON.parse('{"title":"更新履歴","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),i={name:"changelog.md"};function a(t,e,r,n,s,u){return c(),d("div",null,[...e[0]||(e[0]=[l('<h1 id="更新履歴" tabindex="-1">更新履歴 <a class="header-anchor" href="#更新履歴" aria-label="Permalink to &quot;更新履歴&quot;">​</a></h1><h3 id="_1-5-4-2026-04-19" tabindex="-1">[1.5.4] - 2026-04-19 <a class="header-anchor" href="#_1-5-4-2026-04-19" aria-label="Permalink to &quot;[1.5.4] - 2026-04-19&quot;">​</a></h3><h4 id="バグ修正" tabindex="-1">バグ修正 <a class="header-anchor" href="#バグ修正" aria-label="Permalink to &quot;バグ修正&quot;">​</a></h4><ul><li><p><strong>BUG-01 (pop hook lock): <code>pop()</code> の <code>before_delete</code> フックをロック内へ移動</strong>（<code>core.py</code>）</p><ul><li><code>pop()</code> の非 v2 モードで <code>before_delete</code> フックがロック外で呼ばれていたため、<code>__delitem__</code> の SEC-05 修正との一貫性が失われていました。</li><li>非 v2 パスで <code>before_delete</code> の呼び出しを <code>_acquire_lock()</code> ブロック内に移動し、フック実行と DB 削除をアトミックに実行するよう修正しました。<code>self._lock</code> は <code>threading.RLock</code> のため同一スレッドからの再入呼び出しもデッドロックしません。</li><li>また、フックが例外を送出した場合に DB 削除が実行されず、キーが保持されることを確認しました。</li></ul></li><li><p><strong>BUG-02 (batch_update hook result): <code>batch_update()</code> でフック変換値を常に適用</strong>（<code>core.py</code>）</p><ul><li><code>batch_update()</code> の非 coerce パスにおいて <code>before_write</code> フックの返り値が無視されていたため、<code>PydanticHook</code> などの変換フックが <code>__setitem__</code> では機能するのに <code>batch_update()</code> では機能しないサイレントな不整合が発生していました。</li><li><code>if self._coerce:</code> の 2 分岐構造を廃止し、統一された copy-on-write パターンに変更しました。フックが値を変更しない場合は新しい dict は生成されません（メモリ効率を維持）。</li><li><code>ValidkitHook</code> は <code>coerce=False</code> 時に自身でフック内部で変換を行わないため、既存の coerce=False テストとの後方互換性は維持されています。</li></ul></li><li><p><strong>BUG-03 (batch_delete hook lock): <code>batch_delete()</code> の <code>before_delete</code> フックをロック内へ移動</strong>（<code>core.py</code>）</p><ul><li><code>batch_delete()</code> の非 v2 モードで <code>before_delete</code> フックがロック外で呼ばれていました。</li><li>v2 モードではフックはロック外（<code>__delitem__</code> v2 パスと同様）、非 v2 モードではロック内で実行するよう修正しました。</li></ul></li></ul><h4 id="セキュリティ修正" tabindex="-1">セキュリティ修正 <a class="header-anchor" href="#セキュリティ修正" aria-label="Permalink to &quot;セキュリティ修正&quot;">​</a></h4><ul><li><strong>SEC-05: <code>UniqueHook</code> TOCTOU 競合状態の修正</strong>（<code>core.py</code>, <code>hooks.py</code>） <ul><li><code>__setitem__</code> において <code>before_write</code> フックの呼び出しをロックの外側で行っていたため、マルチスレッド環境で UniqueHook の一意性チェックと DB 書き込みの間に別スレッドが割り込む TOCTOU 競合が発生していました。</li><li>非 v2 モードでは <code>__setitem__</code> の <code>before_write</code> および <code>__delitem__</code> の <code>before_delete</code> の呼び出しを <code>_acquire_lock()</code> の内側に移動し、一意性チェック・削除前チェックと DB 更新をアトミックに実行するよう修正しました。<code>self._lock</code> は <code>threading.RLock</code> のためフックからの再入呼び出しでもデッドロックは発生しません。</li><li>UniqueHook の docstring を更新し「WARNING」を削除して修正済みの動作を記載しました（SEC-03 → SEC-05）。</li><li>v2 モードでは非同期フラッシュ構造上の制約があるため、v2 モードでの厳格な一意制約には SQLite UNIQUE 制約の使用を推奨します。</li></ul></li></ul><h4 id="セキュリティ強化" tabindex="-1">セキュリティ強化 <a class="header-anchor" href="#セキュリティ強化" aria-label="Permalink to &quot;セキュリティ強化&quot;">​</a></h4><ul><li><strong>SEC-06 opt-in: <code>google-re2</code> による ReDoS 対策強化</strong>（<code>compat.py</code>, <code>hooks.py</code>, <code>pyproject.toml</code>） <ul><li><code>pip install nanasqlite[re2]</code> で <code>google-re2</code>（RE2 エンジン）をインストールすると、<code>BaseHook</code> のすべての正規表現コンパイルおよびマッチングに RE2 エンジンが使用されます。</li><li>RE2 エンジンは線形時間計算量を保証するため、どんなパターンでも ReDoS 攻撃が不可能になります。</li><li>RE2 利用時は <code>logging.debug</code> でメッセージを出力します（<code>nanasqlite.compat</code> ロガー）。</li><li>RE2 非インストール時は従来通りの危険パターンブラックリスト検証が機能します。</li><li><code>pyproject.toml</code> に <code>re2 = [&quot;google-re2&gt;=1.1&quot;]</code> オプション依存と <code>all</code> extras への追加。</li><li><code>dev</code> extras にも <code>google-re2&gt;=1.1</code> を追加し、CI テストで実際の RE2 エンジンを使用するよう変更。</li><li>エラーメッセージを更新し <code>pip install nanasqlite[re2]</code> への案内を追記。</li><li><strong><code>re_fallback</code> パラメータを <code>BaseHook</code> に追加</strong>: RE2 が対応していないパターン（後方参照 <code>(\\w)\\1</code>、先読み <code>(?=...)</code> 等）を使用した場合のフォールバック動作を制御。 <ul><li><code>re_fallback=False</code>（デフォルト）: RE2 の <code>re2.Error</code> をそのまま伝播させ、ReDoS 保護を維持。</li><li><code>re_fallback=True</code>: <code>warnings.warn</code> を出力した上で標準 <code>re</code> エンジンにフォールバック。このパターンでは ReDoS 保護が無効になります。</li></ul></li></ul></li></ul><h4 id="パフォーマンス改善" tabindex="-1">パフォーマンス改善 <a class="header-anchor" href="#パフォーマンス改善" aria-label="Permalink to &quot;パフォーマンス改善&quot;">​</a></h4><ul><li><p><strong>PERF-01: <code>UniqueHook</code> — <code>use_index=True</code> opt-in 逆引きインデックス</strong>（<code>hooks.py</code>）</p><ul><li>従来 <code>before_write</code> のたびに <code>db.items()</code> で全件スキャン（O(N)）していたため、大規模テーブルで著しいボトルネックになっていました。</li><li><code>UniqueHook(&quot;email&quot;, use_index=True)</code> を指定すると、最初の書き込み時にのみ O(N) の逆引きインデックスを構築し、以降の一意性チェックを O(1) で実行します。</li><li>インデックスは <code>before_write</code>・<code>before_delete</code> コールバックで自動更新されます。フックライフサイクル外でDBを変更した場合は <code>hook.invalidate_index()</code> でインデックスを再構築できます。</li><li>後方互換: <code>use_index=False</code>（デフォルト）では従来の O(N) 動作が維持されます。</li></ul></li><li><p><strong>PERF-02: <code>BaseHook.__init__</code> — コンパイル済み <code>Pattern</code> 型の再コンパイル省略</strong>（<code>hooks.py</code>）</p><ul><li>非 RE2 モードで既コンパイル済みの <code>re.Pattern</code> オブジェクトを渡した場合、<code>re.compile()</code> による再コンパイルを省略してコンパイル済みオブジェクトをそのまま利用します。</li><li>セキュリティ上の要件として、<code>pattern.pattern</code> テキストに対する <code>_validate_regex_pattern</code> の ReDoS バリデーションは引き続き実行されます（コンパイル済み Pattern を経由してブラックリストを迂回できないよう保証）。</li><li>これにより安全性を維持したままフック初期化時のオーバーヘッドを削減しました。</li></ul></li></ul><h4 id="セキュリティ強化-前倒し" tabindex="-1">セキュリティ強化（前倒し） <a class="header-anchor" href="#セキュリティ強化-前倒し" aria-label="Permalink to &quot;セキュリティ強化（前倒し）&quot;">​</a></h4><ul><li><strong>SEC-01: DLQ ペイロード漏洩リスクのドキュメント化</strong>（<code>v2_engine.py</code>） <ul><li>DLQ エントリには KVS の <code>op[&quot;value&quot;]</code>（シリアライズ済み値）が含まれるため、非暗号化DBでは <code>get_dlq()</code> 経由でプレーンテキスト値が外部に漏洩するリスクがあります。</li><li><code>DLQEntry</code> dataclass・<code>_add_to_dlq()</code>・<code>get_dlq()</code> の各 docstring に <strong>SEC-01</strong> セキュリティ注記を追加し、本番環境でのロギング・モニタリング連携時の注意点を明記しました。</li></ul></li></ul><h4 id="コード品質改善-前倒し" tabindex="-1">コード品質改善（前倒し） <a class="header-anchor" href="#コード品質改善-前倒し" aria-label="Permalink to &quot;コード品質改善（前倒し）&quot;">​</a></h4><ul><li><p><strong>QUAL-01: <code>compat.py</code> — <code>re2_module</code> 型アノテーション改善</strong>（<code>compat.py</code>）</p><ul><li><code>re2_module = None # type: ignore[assignment]</code> を <code>re2_module: types.ModuleType | None = None</code> に変更し、mypy が使用箇所で型を追跡できるようにしました。</li></ul></li><li><p><strong>QUAL-02: <code>v2_engine.py</code> — <code>DLQEntry</code> dataclass 導入</strong>（<code>v2_engine.py</code>）</p><ul><li>DLQ の内部表現を <code>list[tuple[str, Any, float]]</code> から <code>list[DLQEntry]</code> に変更しました。<code>DLQEntry</code> は <code>dataclass</code> で定義された明示的な型です。<code>get_dlq()</code> の戻り値（<code>list[dict]</code>）は後方互換を維持します。</li></ul></li></ul><h4 id="テスト追加" tabindex="-1">テスト追加 <a class="header-anchor" href="#テスト追加" aria-label="Permalink to &quot;テスト追加&quot;">​</a></h4><ul><li><code>tests/test_audit_poc.py</code>: <ul><li><code>TestBug01V154PopBeforeDeleteLock</code>: <code>pop()</code> の <code>before_delete</code> フックがロック内で実行されることを確認（3 テスト）</li><li><code>TestBug02V154BatchUpdateHookResult</code>: <code>batch_update()</code> でフック変換値が正しく適用されることを確認（4 テスト）</li><li><code>TestBug03V154BatchDeleteBeforeDeleteLock</code>: <code>batch_delete()</code> の <code>before_delete</code> フックがロック内で実行されることを確認（3 テスト）</li><li><code>TestPerf01V154UniqueHookIndex</code>: <code>UniqueHook</code> の <code>use_index=True</code> 逆引きインデックスを検証（8 テスト）</li><li><code>TestPerf02V154BaseHookPatternRevalidation</code>: 既コンパイル済み Pattern の再バリデーション省略を確認（3 テスト）</li><li><code>TestQual01V154Re2ModuleAnnotation</code>: <code>compat.py</code> の <code>re2_module</code> 型アノテーション改善を確認（2 テスト）</li><li><code>TestQual02V154DLQEntryDataclass</code>: <code>DLQEntry</code> dataclass の導入を確認（3 テスト）</li><li><code>TestSec01V154DLQPayloadDocumentation</code>: DLQ ペイロード漏洩ドキュメントを確認（3 テスト）</li><li><code>TestSec05UniqueHookTOCTOUFix</code>: TOCTOU 修正を検証するテスト（並行書き込み、ロック内フック実行確認、自己更新テスト）を追加</li><li><code>TestRE2Integration</code>: google-re2 統合テスト（<code>HAS_RE2</code> フラグ、パターンコンパイル、RE2 危険パターン許容、RE2 なし時のブラックリスト維持）を追加</li><li><code>TestV150Sec03UniqueHookRace</code>: docstring 検証を旧「WARNING」から新「SEC-05/RLock」記述に更新</li><li><code>TestV150Sec05BaseHookRedos</code>: RE2 インストール時でも <code>HAS_RE2 = False</code> を強制して非 RE2 経路のブラックリスト検証を行うよう更新</li></ul></li><li><code>tests/test_tdd_cycle_4.py</code>: <ul><li><code>test_batch_update_uses_copy_on_write_pattern</code>: <code>batch_update()</code> が統一 copy-on-write パターンを使用することを確認</li></ul></li></ul><hr><h3 id="_1-5-3-2026-04-08" tabindex="-1">[1.5.3] - 2026-04-08 <a class="header-anchor" href="#_1-5-3-2026-04-08" aria-label="Permalink to &quot;[1.5.3] - 2026-04-08&quot;">​</a></h3><h4 id="パフォーマンス改善-1" tabindex="-1">パフォーマンス改善 <a class="header-anchor" href="#パフォーマンス改善-1" aria-label="Permalink to &quot;パフォーマンス改善&quot;">​</a></h4><ul><li><p><strong>PERF-E: <code>_get_all_keys_from_db()</code> — SQL 文字列を事前計算</strong>（<code>core.py</code>）</p><ul><li><code>keys()</code> / <code>__iter__</code> が呼ばれるたびに <code>f&quot;SELECT key FROM {self._safe_table}&quot;</code> を構築していました。PERF-07 と同様に <code>_sql_kv_select_keys</code> を <code>__init__</code> 時に一度だけ計算し、以降はこれを再利用するよう変更しました。</li></ul></li><li><p><strong>PERF-F: <code>batch_update_partial()</code> v2 + Unbounded モード — 不要ロックを除去</strong>（<code>core.py</code>）</p><ul><li>v2 モード + Unbounded モードの組み合わせで、純粋なメモリ更新（<code>_data.update()</code> / <code>_absent_keys.difference_update()</code>）にまでロックを取得していました。<code>batch_update()</code> v2 パスと同様、GIL が個々の dict/set 操作をアトミックに保護するため明示的ロックは不要です。LRU/TTL モードは引き続きロックを取得します。</li></ul></li></ul><h4 id="コード品質改善" tabindex="-1">コード品質改善 <a class="header-anchor" href="#コード品質改善" aria-label="Permalink to &quot;コード品質改善&quot;">​</a></h4><ul><li><p><strong>QUAL-04: <code>_no_encrypt</code> — 変更不可であることのコメント追加</strong>（<code>core.py</code>）</p><ul><li><code>_fernet</code> / <code>_aead</code> が <code>__init__</code> 後に変更された場合、<code>_no_encrypt</code> がステールになりシリアライズが壊れることを明記しました（rc3 監査で指摘、今回対応）。</li></ul></li><li><p><strong>QUAL-05: 型アノテーション修正 — <code>parameters: tuple = None</code> → <code>parameters: tuple | None = None</code></strong>（<code>core.py</code>）</p><ul><li><code>fetch_one()</code>, <code>fetch_all()</code>, <code>create_table()</code> の <code>primary_key</code>、<code>sql_update()</code>, <code>sql_delete()</code>, <code>exists()</code> の 6 箇所で <code>tuple = None</code> を <code>tuple | None = None</code> に修正しました。</li></ul></li><li><p><strong>QUAL-06: <code>async_core.py</code> — <code>_ensure_initialized()</code> 呼び出しの統一</strong>（<code>async_core.py</code>）</p><ul><li><code>query_with_pagination()</code> と <code>table()</code> で <code>if self._db is None: await self._ensure_initialized()</code> という不完全なガードが使われていました。他のメソッドと同様に無条件で <code>await self._ensure_initialized()</code> を呼ぶよう変更しました（<code>_ensure_initialized()</code> 自体がべき等です）。</li></ul></li></ul><hr><h3 id="_1-5-3rc4-2026-04-08" tabindex="-1">[1.5.3rc4] - 2026-04-08 <a class="header-anchor" href="#_1-5-3rc4-2026-04-08" aria-label="Permalink to &quot;[1.5.3rc4] - 2026-04-08&quot;">​</a></h3><h4 id="パフォーマンス改善-2" tabindex="-1">パフォーマンス改善 <a class="header-anchor" href="#パフォーマンス改善-2" aria-label="Permalink to &quot;パフォーマンス改善&quot;">​</a></h4><ul><li><p><strong>PERF-A: <code>_sanitize_identifier()</code> — <code>lru_cache(maxsize=256)</code> を追加</strong>（<code>core.py</code>）</p><ul><li>テーブル名・カラム名の検証は同じ識別子に対して繰り返し呼び出されるにもかかわらず、毎回 <code>re.match()</code> を実行していました。<code>@lru_cache</code> でキャッシュすることで、2 回目以降は dict ルックアップのみになります。</li><li><code>test_begin_commit</code> で約 13% 高速化、<code>sql_insert</code> ホットパスで関数呼び出し 4 倍削減。</li></ul></li><li><p><strong>PERF-B: <code>ExpiringDict.__setitem__()</code> — TIMER モード以外での <code>_cancel_timer()</code> を省略</strong>（<code>utils.py</code>）</p><ul><li>SCHEDULER モードでは <code>_timers</code> / <code>_async_tasks</code> は常に空のため、<code>_cancel_timer()</code> 呼び出しは毎回無意味な dict ルックアップを 2 回実行していました。<code>if self._mode == ExpirationMode.TIMER:</code> ガードで省略します。</li><li><code>test_cache_write_1000[ttl]</code> で約 22% 高速化。</li></ul></li><li><p><strong>PERF-C: <code>vacuum()</code> — <code>execute()</code> ディスパッチをバイパス</strong>（<code>core.py</code>）</p><ul><li><code>vacuum()</code> が <code>execute()</code> の完全なパス（v2 ルーティング、重複 <code>_check_connection</code>、<code>try/except</code> ラップ）を経由していました。<code>begin_transaction</code> / <code>commit</code> / <code>rollback</code> で使用されている PERF-26 パターン（直接接続呼び出し）を適用しました。</li></ul></li><li><p><strong>PERF-D: <code>backup()</code> — DB ファイルの <code>(st_dev, st_ino)</code> を <code>__init__</code> 時にキャッシュ</strong>（<code>core.py</code>）</p><ul><li><code>backup()</code> のセルフコピー防止チェックが毎回 <code>os.stat()</code> を 2 回呼び出していました。ソース DB のスタット結果を <code>__init__</code> 時にキャッシュし（<code>restore()</code> 後に再計算）、<code>backup()</code> では <code>dest_path</code> の 1 回分のみ呼び出すようにしました。</li></ul></li></ul><h4 id="バグ修正-1" tabindex="-1">バグ修正 <a class="header-anchor" href="#バグ修正-1" aria-label="Permalink to &quot;バグ修正&quot;">​</a></h4><ul><li><p><strong>BUG-02: <code>ExpiringDict.clear()</code> — スケジューラスレッドを永久に停止していた問題を修正</strong>（<code>utils.py</code>）</p><ul><li><code>clear()</code> 後に <code>_scheduler_running = False</code> のまま再起動されなかったため、<code>clear()</code> 後に追加された新しい項目が期限切れにならない問題がありました。<code>clear()</code> の完了後にスケジューラを再起動するよう修正しました。</li></ul></li><li><p><strong>BUG-03: <code>UnboundedCache.delete()</code> — <code>_cached_keys</code> に <code>.add()</code> ではなく <code>.discard()</code> を使用</strong>（<code>cache.py</code>）</p><ul><li>削除されたキーが <code>_cached_keys.add(key)</code> によって「キャッシュ済み」としてマークされていたため、再挿入後も DB へのフェッチがスキップされる問題がありました。<code>.discard(key)</code> に修正しました。</li></ul></li><li><p><strong>BUG-04: <code>ExpiringDict.__getitem__()</code> — TOCTOU 競合状態を修正</strong>（<code>utils.py</code>）</p><ul><li><code>_check_expiry()</code> がロック外で実行され、その後ロック内で <code>_data[key]</code> が読み取られていました。スケジューラスレッドが間に割り込んでキーを削除すると、まだ有効だったキーに対して偽の <code>KeyError</code> が発生していました。有効期限チェックと読み取りをロック内でアトミックに実行するよう修正しました。</li></ul></li></ul><h4 id="セキュリティ修正-1" tabindex="-1">セキュリティ修正 <a class="header-anchor" href="#セキュリティ修正-1" aria-label="Permalink to &quot;セキュリティ修正&quot;">​</a></h4><ul><li><strong>SEC-02: <code>create_table()</code> — カラム型正規表現からクォート文字を除去</strong>（<code>core.py</code>） <ul><li>旧正規表現 <code>r&quot;^[\\w\\s(),.+*&#39;\\&quot;]+&quot;</code> がシングル・ダブルクォートを許可していたため、<code>TEXT DEFAULT &#39;x&#39;) --</code> のような SQL インジェクション文字列が通過していました。クォート文字（<code>&#39;</code> <code>&quot;</code>）、セミコロン（<code>;</code>）、コメント構文（<code>--</code>、<code>/* */</code>）を除外した新しい正規表現に変更しました。</li></ul></li></ul><h4 id="コード品質改善-1" tabindex="-1">コード品質改善 <a class="header-anchor" href="#コード品質改善-1" aria-label="Permalink to &quot;コード品質改善&quot;">​</a></h4><ul><li><p><strong>QUAL-01: <code>get_model()</code> — 型アノテーション修正</strong>（<code>core.py</code>）</p><ul><li><code>model_class: type = None</code> を <code>model_class: type | None = None</code> に修正しました。</li></ul></li><li><p><strong>CodeQL: <code>except OSError: pass</code> — 説明コメントを追加</strong>（<code>core.py</code>）</p><ul><li>PERF-D の <code>_db_stat_key</code> キャッシュ初期化時の空 <code>except</code> 節に、CodeQL 指摘に従い説明コメントを追加しました。</li></ul></li></ul><hr><h3 id="_1-5-3rc3-2026-04-07" tabindex="-1">[1.5.3rc3] - 2026-04-07 <a class="header-anchor" href="#_1-5-3rc3-2026-04-07" aria-label="Permalink to &quot;[1.5.3rc3] - 2026-04-07&quot;">​</a></h3><h4 id="パフォーマンス改善-3" tabindex="-1">パフォーマンス改善 <a class="header-anchor" href="#パフォーマンス改善-3" aria-label="Permalink to &quot;パフォーマンス改善&quot;">​</a></h4><ul><li><p><strong>PERF-21: <code>execute_many()</code> — Python ループ → <code>cursor.executemany()</code> に変更</strong>（<code>core.py</code>）</p><ul><li><code>execute_many()</code> の実装がバインドパラメータのリストを Python の <code>for</code> ループで一件ずつ <code>cursor.execute()</code> していました。APSW 組み込みの <code>cursor.executemany()</code> を使うことで Python 側の関数呼び出しオーバーヘッドを排除しました。</li><li>影響テスト: <code>test_execute_many</code>・<code>test_import_from_dict_list</code> で約 15% 高速化。</li></ul></li><li><p><strong>PERF-22: <code>batch_delete()</code> — フック未登録時の事前チェックループを省略</strong>（<code>core.py</code>）</p><ul><li><code>batch_delete()</code> は削除前に全キーに対して <code>_ensure_cached()</code> を呼び出していましたが、その唯一の目的は <code>before_delete</code> フックの呼び出しでした。<code>_has_hooks</code> が <code>False</code> の場合（デフォルト）にはこのループ全体を完全にスキップするよう変更しました。</li><li>影響テスト: <code>test_batch_delete</code> でフックなし時のオーバーヘッドを削減。</li></ul></li><li><p><strong>PERF-23: <code>batch_update()</code> — シリアライズをロック外へ移動・<code>dict.update()</code> 使用・<code>_absent_keys</code> ガード追加</strong>（<code>core.py</code>）</p><ul><li>シリアライズ（<code>_serialize()</code> 呼び出し）は SQLite 接続に触れない純粋な Python/JSON 処理であるため、<code>_acquire_lock()</code> の外に移動しました（<code>__setitem__</code> と同様の方針）。</li><li>Unbounded モードのキャッシュ更新を per-key 代入ループから <code>dict.update()</code> に変更しました。<code>dict.update()</code> は C レベルで実装されており、Python ループの約 6 倍高速です。</li><li>v2 パスも同様に <code>dict.update()</code> + ガードを適用。</li><li><code>_absent_keys.discard()</code> の per-key 呼び出しを <code>if self._absent_keys: self._absent_keys.difference_update(mapping.keys())</code> に置き換え、空セット時のハッシュ計算を完全に排除しました。</li><li>影響テスト: <code>test_batch_write_100</code>・<code>test_batch_update_partial_100</code> で約 9% 高速化。</li></ul></li><li><p><strong>PERF-24: <code>batch_update_partial()</code> — <code>dict.update()</code> + <code>_absent_keys</code> ガード適用</strong>（<code>core.py</code>）</p><ul><li><code>batch_update()</code> (PERF-23) と同様の最適化を <code>batch_update_partial()</code> の v1 / v2 両パスに適用しました。</li></ul></li><li><p><strong>PERF-25: <code>batch_delete()</code> — <code>_absent_keys.add()</code> per-key → <code>_absent_keys.update(keys)</code> に変更</strong>（<code>core.py</code>）</p><ul><li>削除後のキャッシュ更新で、キーごとに <code>_absent_keys.add(key)</code> を呼び出していたものを <code>_absent_keys.update(keys)</code> の一括呼び出しに変更しました。ハッシュ計算コストとセット内部の再割り当て回数を削減します。</li><li>v2 パスも同様に変更。</li></ul></li><li><p><strong>PERF-26: <code>begin_transaction()</code> / <code>commit()</code> / <code>rollback()</code> — <code>execute()</code> オーバーヘッドをバイパス</strong>（<code>core.py</code>）</p><ul><li>これらのメソッドは内部で <code>self.execute(&quot;BEGIN IMMEDIATE&quot;)</code> 等を呼び出していましたが、<code>execute()</code> には v2 モード判定・SQL 文字列の <code>strip().upper()</code> 処理・追加の <code>_check_connection()</code> 呼び出しが含まれます。<code>with self._acquire_lock(): self._connection.execute(...)</code> を直接使うことでこれらのオーバーヘッドを排除しました。</li><li>影響テスト: <code>test_context_manager_transaction</code>・<code>test_begin_commit</code>・<code>test_begin_rollback</code> で高速化。</li></ul></li><li><p><strong>PERF-29: <code>_serialize()</code> — 暗号化なし時の早期リターン</strong>（<code>core.py</code>）</p><ul><li><code>__init__</code> 時に <code>_no_encrypt: bool</code> フラグを事前計算し、暗号化が無効な場合（デフォルト）は <code>if self._fernet:</code> / <code>if self._aead:</code> の 2 回の属性ルックアップをスキップして即座に返すようにしました（PERF-20 と同様の手法）。</li><li>影響テスト: <code>test_nested_write</code>・<code>test_write_encryption[plaintext]</code>・その他全書き込みパスで微小な高速化。</li></ul></li></ul><hr><h3 id="_1-5-3rc2-2026-04-07" tabindex="-1">[1.5.3rc2] - 2026-04-07 <a class="header-anchor" href="#_1-5-3rc2-2026-04-07" aria-label="Permalink to &quot;[1.5.3rc2] - 2026-04-07&quot;">​</a></h3><h4 id="バグ修正-2" tabindex="-1">バグ修正 <a class="header-anchor" href="#バグ修正-2" aria-label="Permalink to &quot;バグ修正&quot;">​</a></h4><ul><li><strong>[Medium] BUG-01: <code>setdefault()</code> + <code>before_write</code> 変換フック組み合わせ時の返値誤り</strong>（<code>core.py</code>） <ul><li>PERF-18 最適化で <code>self[key] = default</code> 後に <code>self[key]</code> を再読み込みせず直接 <code>default</code> を <code>after_read</code> フックに渡す実装としましたが、<code>ValidkitHook(coerce=True)</code> や <code>PydanticHook</code> のように <code>before_write</code> フックが値を変換する場合に誤った値を返す問題がありました（例: <code>&quot;hello&quot;</code> → <code>&quot;HELLO&quot;</code> と変換されるフックがあっても <code>&quot;hello&quot;</code> を返してしまう）。</li><li><strong>修正</strong>: <code>self[key] = default</code> の後、<code>_has_hooks</code> が True の場合はキャッシュから実際に格納された値を読み直してから <code>after_read</code> フックを適用するよう変更しました。フックがない場合は従来どおり <code>default</code> を直接返します（パフォーマンス最適化を維持）。</li><li>対応する POC: <code>etc/poc/poc_bug01_setdefault_coerce_hook.py</code></li></ul></li></ul><h4 id="パフォーマンス修正-v1-5-3rc2-ベンチマーク低下対応" tabindex="-1">パフォーマンス修正（v1.5.3rc2 ベンチマーク低下対応） <a class="header-anchor" href="#パフォーマンス修正-v1-5-3rc2-ベンチマーク低下対応" aria-label="Permalink to &quot;パフォーマンス修正（v1.5.3rc2 ベンチマーク低下対応）&quot;">​</a></h4><ul><li><p><strong>[High] PERF-14: Unbounded モード <code>__getitem__</code> の try/except 高速パス</strong>（<code>core.py</code>）</p><ul><li>キャッシュヒット時のホットパスで <code>.get(key, _NOT_FOUND)</code> + センチネル同一性比較を使用していました。Python の辞書直接アクセス <code>d[key]</code> は <code>try/except KeyError</code> パターンで呼び出すと、センチネルオブジェクト生成・キーワード引数処理・同一性比較が不要になり約 1.9 倍高速になります。<code>test_single_read_cached</code> で <strong>-15%</strong> の改善を確認。</li><li><code>_ensure_cached()</code>・<code>__getitem__</code>・<code>get()</code> のすべての Unbounded ホットパスに適用しました。</li></ul></li><li><p><strong>[High] PERF-15: Unbounded モード <code>get()</code> の try/except 高速パス</strong>（<code>core.py</code>）</p><ul><li>PERF-14 と同様の最適化を <code>get()</code> メソッドに適用しました。<code>test_read_encryption[fernet]</code> で <strong>-11.6%</strong> の改善を確認。</li></ul></li><li><p><strong>[High] PERF-16: Unbounded モード <code>__contains__</code> の try/except 高速パス</strong>（<code>core.py</code>）</p><ul><li>PERF-14 と同様の最適化を <code>__contains__</code> メソッドに適用しました。</li></ul></li><li><p><strong>[Medium] PERF-17: <code>_update_cache</code> での空セット <code>discard()</code> 呼び出し省略</strong>（<code>core.py</code>）</p><ul><li>v1.5.2 の <code>_absent_keys</code> 導入以降、<code>_update_cache()</code> は毎回 <code>self._absent_keys.discard(key)</code> を呼んでいました。書き込み中心のワークロードでは <code>_absent_keys</code> は空のままのため、無駄なハッシュ計算が発生していました。<code>if self._absent_keys:</code> ガードを追加し、空セットの場合はスキップするよう変更しました。</li></ul></li><li><p><strong>[Medium] PERF-18: <code>setdefault()</code> の冗長な <code>self[key]</code> 呼び出し省略</strong>（<code>core.py</code>）</p><ul><li><code>setdefault()</code> はキーが存在しない場合に <code>self[key] = default</code> で書き込み後、さらに <code>self[key]</code> で読み戻していました。書き込み後の値はすでに既知であるため、再度の <code>__getitem__</code> 呼び出しを省略してデフォルト値を直接返すよう変更しました。また Unbounded モードでは <code>_cache.get()</code> のポリモーフィックな呼び出しを <code>_data[key]</code> 直接アクセスに置き換えました。</li></ul></li><li><p><strong>[Medium] PERF-19: <code>pop()</code> の Unbounded モードでの直接 <code>_data</code> アクセス</strong>（<code>core.py</code>）</p><ul><li><code>pop()</code> は値の取得に <code>self._cache.get(key)</code> を使用していました。Unbounded モードでは <code>_data</code> に実値が直接格納されているため、<code>self._data[key]</code> で取得することでポリモーフィックなメソッドディスパッチ（LRU では <code>move_to_end()</code> を伴う）を回避できます。</li></ul></li><li><p><strong>[Medium] PERF-20: <code>_has_hooks</code> 事前計算フラグによる全ホットパスの高速化</strong>（<code>core.py</code>）</p><ul><li><code>__getitem__</code>・<code>__setitem__</code>・<code>__delitem__</code>・<code>get()</code>・<code>get_fresh()</code>・<code>batch_get()</code>・<code>pop()</code>・<code>setdefault()</code>・<code>batch_update_partial()</code>・<code>batch_delete()</code> のすべてのホットパスで <code>if self._hooks:</code> を使用していました。これは毎回リストの <code>__len__</code> を呼び出すオーバーヘッドがあります。<code>__init__</code> 時に <code>self._has_hooks: bool = bool(self._hooks)</code> を事前計算し、<code>add_hook()</code> 時も更新するよう変更しました。</li></ul></li></ul><h4 id="テスト" tabindex="-1">テスト <a class="header-anchor" href="#テスト" aria-label="Permalink to &quot;テスト&quot;">​</a></h4><ul><li><code>tests/test_v153_perf_fixes.py</code> に以下を追加（PERF-14〜20 の動作検証 および BUG-01 回帰テスト）: <ul><li>キャッシュヒット時の <code>__getitem__</code> / <code>get()</code> / <code>__contains__</code> の正確性</li><li><code>_update_cache</code> の空 <code>_absent_keys</code> 時のスキップ動作</li><li><code>setdefault()</code> の新キー・既存キーの返値（フックあり・なし）</li><li><code>pop()</code> の Unbounded モードでの正確性</li><li><code>_has_hooks</code> の初期化・<code>add_hook()</code> 後の更新確認</li><li>BUG-01: <code>before_write</code> 変換フック付き <code>setdefault()</code> の正確な返値検証</li></ul></li></ul><h3 id="_1-5-3rc1-2026-04-07" tabindex="-1">[1.5.3rc1] - 2026-04-07 <a class="header-anchor" href="#_1-5-3rc1-2026-04-07" aria-label="Permalink to &quot;[1.5.3rc1] - 2026-04-07&quot;">​</a></h3><h4 id="パフォーマンス修正-v1-5-3-プレリリース監査" tabindex="-1">パフォーマンス修正（v1.5.3 プレリリース監査） <a class="header-anchor" href="#パフォーマンス修正-v1-5-3-プレリリース監査" aria-label="Permalink to &quot;パフォーマンス修正（v1.5.3 プレリリース監査）&quot;">​</a></h4><ul><li><p><strong>[High] PERF-07: 共通 SQL 文字列の <code>__init__</code> 時事前計算</strong>（<code>core.py</code>）</p><ul><li><code>__setitem__</code>・<code>__delitem__</code>・<code>__contains__</code>・<code>__len__</code>・<code>_write_to_db</code>・<code>_read_from_db</code>・<code>_delete_from_db</code>・<code>load_all</code>・<code>batch_update</code>・<code>batch_delete</code> の全ホットパスで、毎呼び出し f-string によって同一の SQL 文字列（テーブル名を含む INSERT / DELETE / SELECT 等）を再構築していました。<code>__init__</code> 時に 6 種類の SQL テンプレートを事前計算してインスタンス変数に保持し、ホットパスでは直接参照するよう変更しました。</li><li><strong>効果</strong>: 書き込み・読み込み・削除・カウント等の全 KV 操作で文字列構築コストを排除。<code>test_single_write</code> / <code>test_execute_raw</code> / <code>test_sql_insert_single</code> の改善に寄与。</li></ul></li><li><p><strong>[Medium] PERF-08: Unbounded モードでの <code>to_dict()</code> / <code>copy()</code> MISSING フィルタ省略</strong>（<code>core.py</code>）</p><ul><li>Unbounded モードでは <code>_data</code> に MISSING センチネルが格納されることはないため、毎回 <code>{k: v for k, v in _data.items() if v is not MISSING}</code> で全要素の同一性比較を行う必要はありませんでした。Unbounded モードでは <code>dict(self._data)</code> を直接返すよう変更し、LRU/TTL モードでのみフィルタを適用します。</li><li><strong>効果</strong>: <code>test_to_dict_1000</code> / <code>test_copy</code> の改善に寄与。</li></ul></li><li><p><strong>[Medium] PERF-09: LRU <code>__getitem__</code> での二重キャッシュルックアップ排除</strong>（<code>core.py</code>）</p><ul><li>LRU/TTL モードの <code>__getitem__</code> は <code>_ensure_cached()</code> 内部で <code>self._cache.get()</code>（LRU では <code>move_to_end()</code> を伴う）を 1 回呼び、さらに戻り値取得のために同じキーで <code>self._cache.get()</code> を再度呼んでいました。キャッシュヒット時の <code>_data</code> 在籍確認を先行させ、<code>self._cache.get()</code> を 1 回の呼び出しで完結するよう変更しました。</li><li><strong>効果</strong>: LRU/TTL キャッシュヒット時の <code>move_to_end()</code> 冗長呼び出しを排除。<code>test_cache_hit[lru]</code> / <code>test_cache_hit[ttl]</code> の改善に寄与。</li></ul></li><li><p><strong>[Medium] PERF-10: <code>_validate_expression()</code> の正規表現最適化と関数スキャン早期スキップ</strong>（<code>core.py</code>）</p><ul><li><code>_validate_expression()</code> が毎呼び出し 4 つの危険パターン文字列を <code>re.search()</code> で個別にスキャンしていました。4 パターンをモジュールレベルで事前コンパイルした単一正規表現 <code>_DANGEROUS_SQL_RE</code> に統合し、1 回のスキャンで検出するよう変更しました。また、式に <code>(</code> が含まれない場合（典型的な <code>id = ?</code> 等）は高コストな <code>sanitize_sql_for_function_scan()</code> + <code>re.findall()</code> の実行を完全にスキップします。</li><li><strong>注意</strong>: 非 strict モードでは、複数の危険パターンが同時にマッチしても警告は 1 件のみ発行されます（以前は複数件）。strict モード（例外発生）の挙動は変わりません。</li><li><strong>効果</strong>: <code>exists()</code> / <code>sql_update()</code> / <code>sql_delete()</code> のホットパスで複数のシングルパターン regex 走査を排除。<code>test_sql_update_single</code> / <code>test_exists_check</code> / <code>test_execute_raw</code> の改善に寄与。</li></ul></li><li><p><strong>[Medium] PERF-11: <code>ExpiringDict._check_expiry()</code> のロックフリー早期リターン最適化</strong>（<code>utils.py</code>）</p><ul><li><code>_check_expiry()</code> は毎呼び出し <code>threading.RLock</code> を取得していました。TTL キャッシュのヒットパスでは 1 回のキーアクセスにつき複数回 <code>_check_expiry()</code> が呼ばれるため、このロック取得コストが積み重なっていました。CPython の GIL 下では <code>dict.get()</code> はアトミックであるため、ロックなしで <code>_exptimes.get(key)</code> を読み取り、期限切れでない場合は即座に <code>False</code> を返す楽観的プレチェックを追加しました。</li><li><strong>効果</strong>: TTL キャッシュのキャッシュヒット時のロック取得回数を削減。<code>test_cache_hit[ttl]</code> / <code>test_ttl_expiry_check</code> の改善に寄与。</li></ul></li><li><p><strong>[High] PERF-12: LRU/TTL モードの <code>get()</code> における二重キャッシュルックアップ排除</strong>（<code>core.py</code>）（v1.5.3 監査で発見）</p><ul><li>PERF-09 で <code>__getitem__</code> を最適化した際、同じ二重ルックアップ問題が <code>get()</code> メソッドに残存していました。<code>get()</code> は <code>to_dict()</code> / <code>items()</code> のホットパスでも利用されるため影響が大きい問題です。<code>__getitem__</code> と同じパターン（<code>_data</code> 在籍確認 → <code>cache.get()</code> 1 回）を適用しました。</li><li><strong>効果</strong>: LRU/TTL キャッシュヒット時の <code>move_to_end()</code> 冗長呼び出しを <code>get()</code> でも排除。<code>test_cache_hit[lru]</code> / <code>test_cache_hit[ttl]</code> のさらなる改善に寄与。</li></ul></li><li><p><strong>[Medium] PERF-13: Unbounded モードの <code>values()</code> / <code>items()</code> における MISSING フィルタ省略</strong>（<code>core.py</code>）（v1.5.3 監査で発見）</p><ul><li>PERF-08 で <code>to_dict()</code> を最適化した際、同じ最適化が <code>values()</code> と <code>items()</code> に適用されていませんでした。Unbounded モードではこれらも <code>list(self._data.values())</code> / <code>list(self._data.items())</code> を直接返すよう変更しました。</li><li><strong>効果</strong>: <code>test_to_dict_1000</code> / 全データ取得系ホットパスのさらなる改善に寄与。</li></ul></li></ul><h4 id="新規ベンチマークテスト追加" tabindex="-1">新規ベンチマークテスト追加 <a class="header-anchor" href="#新規ベンチマークテスト追加" aria-label="Permalink to &quot;新規ベンチマークテスト追加&quot;">​</a></h4><ul><li><code>tests/test_benchmark.py</code> に <code>test_cache_hit[lru]</code> / <code>test_cache_hit[ttl]</code> を追加。単一キーへの繰り返しアクセスによるキャッシュヒットパスのオーバーヘッドを計測する。</li></ul><h4 id="テスト-1" tabindex="-1">テスト <a class="header-anchor" href="#テスト-1" aria-label="Permalink to &quot;テスト&quot;">​</a></h4><ul><li><code>tests/test_v153_perf_fixes.py</code> を追加し、以下を検証: <ul><li>PERF-07: <code>_sql_kv_*</code> 事前計算属性の存在と正確性</li><li>PERF-08: <code>to_dict()</code> / <code>copy()</code> が Unbounded / LRU 両モードで MISSING を含まないこと</li><li>PERF-09: LRU / TTL <code>__getitem__</code> がキャッシュヒット・不在キーで正しく動作すること</li><li>PERF-10: 単純な WHERE 句・関数付き WHERE 句・危険パターンの検出が正しく機能すること</li><li>PERF-11: <code>ExpiringDict._check_expiry()</code> の有効期限前後の挙動が正しいこと</li></ul></li><li><code>tests/test_audit_poc.py</code> に <code>TestPerf12GetDoubleLookup</code> / <code>TestPerf13ValuesItemsFilter</code> を追加: <ul><li>PERF-12: LRU/TTL <code>get()</code> がキャッシュヒット・不在キーで正しく動作すること</li><li>PERF-13: <code>values()</code> / <code>items()</code> が Unbounded / LRU 両モードで MISSING を含まないこと</li></ul></li></ul><h3 id="_1-5-2-2026-04-06" tabindex="-1">[1.5.2] - 2026-04-06 <a class="header-anchor" href="#_1-5-2-2026-04-06" aria-label="Permalink to &quot;[1.5.2] - 2026-04-06&quot;">​</a></h3><h4 id="パフォーマンス修正-v1-5-0dev1-以降の性能低下-継続対応" tabindex="-1">パフォーマンス修正（v1.5.0dev1 以降の性能低下 継続対応） <a class="header-anchor" href="#パフォーマンス修正-v1-5-0dev1-以降の性能低下-継続対応" aria-label="Permalink to &quot;パフォーマンス修正（v1.5.0dev1 以降の性能低下 継続対応）&quot;">​</a></h4><ul><li><strong>[High] PERF-06: Unbounded キャッシュ読み取りホットパスの分岐最適化</strong>（<code>core.py</code>） <ul><li><code>__getitem__</code> / <code>get</code> / <code>__contains__</code> / <code>_ensure_cached</code> の Unbounded モードで、内部メタデータ参照を優先してから <code>_data</code> を確認する経路が残っており、正のキャッシュヒット時にも不要な membership 判定が追加され、キャッシュ済み読み取りで無視できないオーバーヘッドになっていました。</li><li><ol><li><code>_data</code> を先に確認する fast-path に変更（ヒット時は即 return）</li></ol></li><li><ol start="2"><li>known-absent の早期 return は <code>_absent_keys</code> に限定</li></ol></li><li><ol start="3"><li><code>__getitem__</code> / <code>get</code> でも同様の fast-path を適用し、不要な <code>_ensure_cached()</code> 呼び出しを回避</li></ol></li><li><strong>効果</strong>: キャッシュ済み読み取り・存在確認の追加オーバーヘッドを削減（既存 API/挙動は維持）。</li></ul></li></ul><h4 id="破壊的変更-許可済み対応" tabindex="-1">破壊的変更（許可済み対応） <a class="header-anchor" href="#破壊的変更-許可済み対応" aria-label="Permalink to &quot;破壊的変更（許可済み対応）&quot;">​</a></h4><ul><li>Unbounded モードの内部メタデータを <code>_cached_keys</code> から <code>_absent_keys</code>（known-absent 専用）へ分離しました。 <ul><li>公開 API への影響はありませんが、内部属性 <code>_cached_keys</code> に依存するコードは互換性がありません。</li><li>移行: <code>in</code> / <code>get</code> / <code>is_cached</code> 等の公開 API を利用してください。</li></ul></li></ul><h4 id="テスト-2" tabindex="-1">テスト <a class="header-anchor" href="#テスト-2" aria-label="Permalink to &quot;テスト&quot;">​</a></h4><ul><li><code>tests/test_v152_perf_fastpath.py</code> を追加し、以下を検証: <ul><li>Unbounded モードで <code>_data</code> 優先 fast-path が機能すること</li><li>既知の不在キー（negative cache）挙動が維持されること</li></ul></li></ul><h4 id="監査-etc-audit-audit-prompt-md-準拠" tabindex="-1">監査（<code>etc/audit/audit_prompt.md</code> 準拠） <a class="header-anchor" href="#監査-etc-audit-audit-prompt-md-準拠" aria-label="Permalink to &quot;監査（`etc/audit/audit_prompt.md` 準拠）&quot;">​</a></h4><ul><li>フェーズ1〜6の観点で差分監査を実施し、今回の修正範囲（read/contains ホットパス）において: <ul><li>後方互換性を壊す変更なし</li><li>新規セキュリティ問題の導入なし</li><li>既存の negative cache セマンティクス維持を確認</li></ul></li></ul><h3 id="_1-5-1-2026-04-05" tabindex="-1">[1.5.1] - 2026-04-05 <a class="header-anchor" href="#_1-5-1-2026-04-05" aria-label="Permalink to &quot;[1.5.1] - 2026-04-05&quot;">​</a></h3><h4 id="セキュリティ修正-v1-5-1-プレリリース監査" tabindex="-1">セキュリティ修正（v1.5.1 プレリリース監査） <a class="header-anchor" href="#セキュリティ修正-v1-5-1-プレリリース監査" aria-label="Permalink to &quot;セキュリティ修正（v1.5.1 プレリリース監査）&quot;">​</a></h4><ul><li><p><strong>[Medium] SEC-01: <code>exists()</code> の WHERE 句に <code>_validate_expression()</code> 未適用を修正</strong>（<code>core.py</code>）</p><ul><li><code>query()</code> / <code>count()</code> / <code>query_with_pagination()</code> は WHERE 句を <code>_validate_expression()</code> で検証して <code>forbidden_sql_functions</code> などのポリシーを適用していましたが、<code>exists()</code> はこの検証を行っていませんでした。アプリケーションが <code>forbidden_sql_functions</code> を設定していても <code>exists()</code> のみポリシーが無視されるという不整合を修正しました。</li><li><code>exists()</code> を呼び出す前に <code>_validate_expression(where, context=&quot;where&quot;)</code> を実行するよう変更しました。</li></ul></li><li><p><strong>[Medium] SEC-02: <code>sql_update()</code> / <code>sql_delete()</code> の WHERE 句に <code>_validate_expression()</code> 未適用を修正</strong>（<code>core.py</code>）</p><ul><li><code>sql_update()</code> と <code>sql_delete()</code> の WHERE 句も同様に <code>_validate_expression()</code> が呼ばれていませんでした。<code>strict_sql_validation=True</code> / <code>forbidden_sql_functions</code> の設定がこれらのメソッドでは機能しない不整合を修正しました。</li></ul></li></ul><h4 id="バグ修正-v1-5-1-プレリリース監査" tabindex="-1">バグ修正（v1.5.1 プレリリース監査） <a class="header-anchor" href="#バグ修正-v1-5-1-プレリリース監査" aria-label="Permalink to &quot;バグ修正（v1.5.1 プレリリース監査）&quot;">​</a></h4><ul><li><p><strong>[High] BUG-01: <code>pop()</code> が v2 モードで v2 エンジンをバイパスする問題を修正</strong>（<code>core.py</code>）</p><ul><li>v2 モードで <code>pop()</code> を呼ぶと <code>_delete_from_db()</code> が直接 DB へ DELETE を発行し、v2 staging buffer を完全にバイパスしていました。staging buffer に SET 操作が残留している状態でこの直接 DELETE が実行されると、その後の <code>flush()</code> で staging の SET が DB に書き込まれてキーが「復活」するデータ整合性バグが発生していました。<code>__delitem__</code> と同様に v2 モードでは <code>v2_engine.kvs_delete()</code> を経由するよう修正しました。</li></ul></li><li><p><strong>[Medium] BUG-02: <code>batch_get()</code> が <code>_cached_keys</code> の「存在しない」ステータスを尊重しない問題を修正</strong>（<code>core.py</code>）</p><ul><li><code>__delitem__</code> 実行後、キーは <code>_cached_keys</code> に「存在しない」として記録されますが、<code>batch_get()</code> は <code>_data</code> のみを確認して <code>_cached_keys</code> を参照しないため、v2 non-immediate モードでは staging の DELETE がまだ DB に反映されていない状態で <code>batch_get()</code> が DB の旧値を返してしまう不整合がありました。<code>batch_get()</code> でも <code>_cached_keys</code> を確認して「既知の不在キー」をスキップするよう修正しました。</li></ul></li><li><p><strong>[Low] BUG-03: <code>to_dict()</code> が LRU/TTL モードで <code>MISSING</code> センチネル値を含む問題を修正</strong>（<code>core.py</code>）</p><ul><li>LRU/TTL キャッシュモードでは、存在しないキーへのアクセス時に <code>MISSING</code> センチネルがキャッシュに書き込まれます（負キャッシュ）。<code>to_dict()</code> がこれをフィルタリングせずに返していたため、結果に <code>{key: &lt;MISSING sentinel&gt;}</code> が混入する可能性がありました。<code>items()</code> と同様に <code>MISSING</code> をフィルタリングするよう修正しました。</li></ul></li></ul><h4 id="パフォーマンス修正-v1-5-1-プレリリース監査" tabindex="-1">パフォーマンス修正（v1.5.1 プレリリース監査） <a class="header-anchor" href="#パフォーマンス修正-v1-5-1-プレリリース監査" aria-label="Permalink to &quot;パフォーマンス修正（v1.5.1 プレリリース監査）&quot;">​</a></h4><ul><li><strong>[Low] PERF-05: <code>fast_validate_sql_chars()</code> のホットパス最適化</strong>（<code>sql_utils.py</code>） <ul><li><code>fast_validate_sql_chars()</code> が呼び出しごとに <code>set(...)</code> で文字セットオブジェクトを新規生成していました。この関数は全てのクエリメソッドのバリデーション経路（ホットパス）から呼ばれるため、モジュールレベルの <code>frozenset</code> 定数 <code>_SAFE_SQL_CHARS</code> として事前計算するよう変更しました。約 200–300 ns / 呼び出しのオーバーヘッドを削減します。</li></ul></li></ul><h4 id="パフォーマンス修正-v1-5-0dev1-以降の性能低下対応" tabindex="-1">パフォーマンス修正（v1.5.0dev1 以降の性能低下対応） <a class="header-anchor" href="#パフォーマンス修正-v1-5-0dev1-以降の性能低下対応" aria-label="Permalink to &quot;パフォーマンス修正（v1.5.0dev1 以降の性能低下対応）&quot;">​</a></h4><p>ベンチマーク（RPI 実機）で確認された v1.5.0dev1 以降の性能低下を修正しました。</p><ul><li><p><strong>[Critical] PERF-01: フックホットパスのオーバーヘッド除去</strong>（<code>core.py</code>）</p><ul><li><code>__getitem__</code>・<code>__setitem__</code>・<code>__delitem__</code>・<code>get</code>・<code>batch_get</code>・<code>setdefault</code>・<code>pop</code>・<code>batch_update_partial</code>・<code>batch_delete</code> の全ての読み書き操作で、毎呼び出し <code>getattr(self, &quot;_hooks&quot;, [])</code> を実行していたため、フックが未設定の場合でも無視できないオーバーヘッドが発生していました。<code>self._hooks</code>（常に初期化済み）への直接アクセスと <code>if self._hooks:</code> による早期スキップに変更しました。</li><li><strong>効果</strong>: キャッシュ済みキーの読み込み速度が約 30% 向上（実機 RPI: ~1.74M → ~2.3M ops/sec 相当）。</li></ul></li><li><p><strong>[Critical] PERF-02: v2 モードにおける共有ロック競合の解消</strong>（<code>core.py</code>）</p><ul><li><code>__setitem__</code>・<code>__delitem__</code>・<code>batch_update</code>・<code>batch_delete</code> の v2 モードパスで、インメモリキャッシュの更新（<code>_data[key] = value</code> 等）に対して DB フラッシュスレッドと共有するロックを使用していました。このため、バックグラウンドフラッシュスレッドが DB トランザクションのためにロックを保持している間、メインスレッドのキャッシュ更新がブロックされ、特に低速 CPU（Raspberry Pi 等）で深刻なスループット低下を引き起こしていました。</li><li>v2 モードにおいてインメモリのみの更新操作は Python の GIL によるアトミック性が保証されており、バックグラウンドフラッシュスレッドは <code>_data</code> / <code>_cached_keys</code> に直接アクセスしないため、これらの操作に対する明示的なロック取得は不要です。</li><li><strong>効果</strong>: v2 immediate モードの書き込みスループットが約 3.7 倍向上（実機 RPI: ~169 → ~600+ calls/sec 相当）。</li></ul></li><li><p><strong>[Medium] PERF-03: <code>_update_cache</code> 内の <code>hasattr()</code> 呼び出しを事前計算に変更</strong>（<code>core.py</code>）</p><ul><li><code>_update_cache()</code> が毎呼び出し <code>hasattr(self._cache, &quot;_max_size&quot;)</code> を実行していたため、書き込みパスで不要なオーバーヘッドが発生していました。<code>__init__</code> 時に <code>_use_cache_set</code> フラグとして事前計算するように変更し、ホットパスから <code>hasattr()</code> 呼び出しを除去しました。</li><li><strong>効果</strong>: 書き込みパスで約 2-3% の速度改善。</li></ul></li><li><p><strong>[Medium] PERF-04: <code>_acquire_lock()</code> を <code>@contextmanager</code> ジェネレータから直接 RLock 返却に変更</strong>（<code>core.py</code>）</p><ul><li><code>_acquire_lock()</code> が <code>@contextmanager</code> デコレータを使用していたため、毎呼び出しでジェネレータオブジェクトの生成・<code>next()</code> 呼び出し・<code>contextlib</code> のオーバーヘッドが発生していました。タイムアウト未設定（共通ケース）の場合は <code>threading.RLock</code> オブジェクトをそのまま返し、タイムアウト設定時のみ新設の <code>_TimedLockContext</code> を返すよう変更しました。<code>RLock</code> は C レベルの <code>__enter__</code>/<code>__exit__</code> を持つため、ジェネレータより大幅に高速です。</li><li><strong>効果</strong>: 非 v2 書き込みで約 7% の速度改善。</li></ul></li></ul><h3 id="_1-5-0-2026-04-04" tabindex="-1">[1.5.0] - 2026-04-04 <a class="header-anchor" href="#_1-5-0-2026-04-04" aria-label="Permalink to &quot;[1.5.0] - 2026-04-04&quot;">​</a></h3><h4 id="セキュリティ修正-v1-5-0-プレリリース監査" tabindex="-1">セキュリティ修正（v1.5.0 プレリリース監査） <a class="header-anchor" href="#セキュリティ修正-v1-5-0-プレリリース監査" aria-label="Permalink to &quot;セキュリティ修正（v1.5.0 プレリリース監査）&quot;">​</a></h4><ul><li><strong>[Critical] SEC-03</strong>: <code>UniqueHook</code> における TOCTOU (Time-of-check/Time-of-use) 競合状態を文書化・警告追加。ユニーク制約チェックが DB 書き込みの外側で行われるため、マルチスレッド環境では制約をバイパスされる可能性があることをクラス docstring に明記しました。本質的な修正には SQLite ネイティブ制約 (<code>UNIQUE</code>) または排他ロックの適用を推奨します。</li><li><strong>[Critical] SEC-04</strong>: <code>ForeignKeyHook</code> における TOCTOU 競合状態を同様に文書化・警告追加。参照整合性制約チェックとDB書き込みの間に参照先キーが削除される可能性を docstring に明記。本質的な修正には <code>PRAGMA foreign_keys=ON</code> の使用を推奨します。</li><li><strong>[High] SEC-05</strong>: <code>BaseHook</code> の <code>key_pattern</code> 正規表現パターンに ReDoS (正規表現によるサービス拒否) 脆弱性が存在しました。悪意ある正規表現パターンにより CPU 負荷を引き起こす可能性があったため、コンストラクト時にパターン検証を行うよう修正しました。</li><li><strong>[High] SEC-06</strong>: フック制約違反時のエラーメッセージに詳細なフィールド名・値が含まれ、情報漏洩の恐れがありました。エラーメッセージを汎用化し、詳細情報はサーバーサイドのログのみに記録するように修正しました。</li></ul><h4 id="バグ修正-v1-5-0-プレリリース監査" tabindex="-1">バグ修正（v1.5.0 プレリリース監査） <a class="header-anchor" href="#バグ修正-v1-5-0-プレリリース監査" aria-label="Permalink to &quot;バグ修正（v1.5.0 プレリリース監査）&quot;">​</a></h4><ul><li><strong>[Critical] BUG-05</strong>: <code>PydanticHook</code> が全ての例外を <code>ValidationError</code> として一律に変換・抑制していた問題を修正。<code>ConnectionError</code>, <code>MemoryError</code> 等のシステムエラーは正しく再送出されるようになりました。</li><li><strong>[High] BUG-06</strong>: フック処理において値が変更されない場合も不要な辞書コピーを行っていた問題を修正。変更検出ロジックを導入し、実際に値が変更された場合のみ新しい辞書を生成するようにしました（バッチ処理でのメモリ効率改善）。</li></ul><h4 id="コード品質修正-pr-レビュー指摘対応" tabindex="-1">コード品質修正（PR レビュー指摘対応） <a class="header-anchor" href="#コード品質修正-pr-レビュー指摘対応" aria-label="Permalink to &quot;コード品質修正（PR レビュー指摘対応）&quot;">​</a></h4><ul><li><strong>[Low] BANDIT-B110</strong>: <code>v2_engine.py</code> にて Bandit が指摘した <code>try/except/pass</code> パターン（<code>atexit.unregister</code> の空キャッチ）を <code>contextlib.suppress(Exception)</code> に置き換え。</li><li><strong>[Low] POC クリーンアップ</strong>: CodeQL・Bandit が指摘した POC スクリプト内の問題（未使用インポート、未使用変数、bare <code>except</code>、ReDoS パターンのリテラル埋め込み）をすべて修正。テストファイル内の重複 <code>import sqlite3</code> も解消。</li></ul><h4 id="パッケージングとide支援の改善" tabindex="-1">パッケージングとIDE支援の改善 <a class="header-anchor" href="#パッケージングとide支援の改善" aria-label="Permalink to &quot;パッケージングとIDE支援の改善&quot;">​</a></h4><ul><li><strong>[High] PEP 561 準拠と型補完の修正</strong>: <ul><li><code>pyproject.toml</code> の <code>tool.setuptools</code> 設定を標準的な <code>src-layout</code> 用に刷新。これまで PyPI 配布版で <code>import nanasqlite</code> した際に型補完（IntelliSense）が効かなかった問題を修正しました。</li><li><code>include-package-data = true</code> を有効化し、<code>MANIFEST.in</code> を追加することで、ビルドされたパッケージ (.whl, sdist) に確実に <code>py.typed</code> ファイルが含まれるようにしました。</li><li>これにより、VS Code (Pylance) や PyCharm 等の主要な IDE で、インストール直後から <code>NanaSQLite</code> や <code>PydanticHook</code> などの完全な型補完が利用可能になりました。</li></ul></li></ul><h4 id="リリース品質監査-release-audit-による改善" tabindex="-1">リリース品質監査 (Release Audit) による改善 <a class="header-anchor" href="#リリース品質監査-release-audit-による改善" aria-label="Permalink to &quot;リリース品質監査 (Release Audit) による改善&quot;">​</a></h4><ul><li><strong>[Critical] BUG-01</strong>: <code>batch_update</code>, <code>batch_update_partial</code>, <code>batch_delete</code> メソッドにおいて V2 モードをバイパスして直接 DB を書き換えていた不具合を修正。V2 エンジンのステージングバッファを経由するようにルーティングし、データの整合性と順序を保証しました。</li><li><strong>[Critical] BUG-02</strong>: <code>clear()</code> および <code>load_all()</code> メソッドにおいて、V2 エンジンの <code>flush()</code> が完了する前に DB 操作が実行され、古いデータが再挿入される「幽霊書き込み（Ghost Re-inserts）」が発生する問題を修正。<code>flush(wait=True)</code> による同期的待機を導入しました。</li><li><strong>[High] QUAL-01</strong>: <code>AsyncNanaSQLite.add_hook()</code> の実装を整理。ベース DB 初期化前後のフック登録処理を堅牢化し、非同期実行時の安定性を向上させました。</li><li><strong>[Non-Breaking] API 拡張</strong>: <code>flush()</code> (同期) および <code>aflush()</code> (非同期) に <code>wait</code> 引数を追加。バックグラウンド処理の完了を待機できるようになりました。</li><li><strong>[High] Python 3.9 互換性の完全復旧</strong>: <ul><li>全てのソースファイルに <code>from __future__ import annotations</code> を追加し、Python 3.10+ の <code>|</code> (Union) 演算子を型ヒントで使用していても Python 3.9 で動作するように修正しました。</li><li><code>compat.py</code> に <code>EllipsisType</code> の互換レイヤーを導入し、Python 3.9 環境での <code>mypy</code> チェックと実行時の型検証の安定性を向上させました。</li><li><code>pyproject.toml</code> の <code>mypy</code> 設定を <code>3.9</code> に更新し、継続的な互換性を保証しました。</li></ul></li></ul><h4 id="新機能-ultimate-hooks-汎用フック-制約アーキテクチャ" tabindex="-1">新機能: Ultimate Hooks (汎用フック＆制約アーキテクチャ) <a class="header-anchor" href="#新機能-ultimate-hooks-汎用フック-制約アーキテクチャ" aria-label="Permalink to &quot;新機能: Ultimate Hooks (汎用フック＆制約アーキテクチャ)&quot;">​</a></h4><ul><li><strong>強力なフック機構の導入</strong>: <ul><li><code>NanaHook</code> プロトコルを新設し、<code>before_write</code>, <code>after_read</code>, <code>before_delete</code> の3つのライフサイクルイベントをフック可能にしました。</li><li>カスタムフックを自作することで、データの検証、暗号化の拡張、ロギング、他システムへの通知などを自由に実装できます。</li></ul></li><li><strong>標準制約（Standard Constraints）の組み込み</strong>: <ul><li><code>CheckHook</code>: SQLite の <code>CHECK</code> 制約のような関数ベースの検証を提供。</li><li><code>UniqueHook</code>: 指定したキー（またはフィールド）の値の一意性を保証（TOCTOU 警告あり、詳細は SEC-03 参照）。</li><li><code>ForeignKeyHook</code>: 他の <code>NanaSQLite</code> テーブルのキーに対する参照整合性を保証（TOCTOU 警告あり、詳細は SEC-04 参照）。</li></ul></li><li><strong>外部ライブラリ統合の透過的サポート</strong>: <ul><li><code>ValidkitHook</code>: 従来の <code>validator</code> 引数と互換性を持ち、<code>validkit-py</code> による高性能バリデーションを提供。</li><li><code>PydanticHook</code>: <code>Pydantic</code> モデルを直接フックに登録することで、読み書き時の自動シリアライズ/デシリアライズおよび厳格な型検証を実現。</li></ul></li><li><strong>メソッドの拡張</strong>: <ul><li><code>NanaSQLite.add_hook()</code> および <code>AsyncNanaSQLite.add_hook()</code> を追加しました。</li></ul></li></ul><h4 id="アーキテクチャ強化と後方互換性" tabindex="-1">アーキテクチャ強化と後方互換性 <a class="header-anchor" href="#アーキテクチャ強化と後方互換性" aria-label="Permalink to &quot;アーキテクチャ強化と後方互換性&quot;">​</a></h4><ul><li>従来の <code>validator</code> パラメータは内部的に <code>ValidkitHook</code> へと自動変換されるようになり、後方互換性が100%維持されています。</li><li><code>batch_update</code>, <code>get</code>, <code>batch_get</code>, <code>setdefault</code>, <code>pop</code> など、あらゆるアクセス経路でフックが等しく適用されるように内部ロジックを統合・堅牢化しました。</li></ul><h4 id="監査・テスト" tabindex="-1">監査・テスト <a class="header-anchor" href="#監査・テスト" aria-label="Permalink to &quot;監査・テスト&quot;">​</a></h4><ul><li>プレリリース監査レポート (<code>audit.md</code>) を更新 — v1.5.0 向け 12 件の発見事項を文書化。</li><li>POC スクリプト 5 件を <code>etc/poc/</code> に追加。</li><li>POC 検証テスト 14 件を <code>tests/test_audit_poc.py</code> に追加。</li></ul><h3 id="_1-5-0dev2-2026-03-28-リリース済みバージョン-—-v1-5-0-に統合" tabindex="-1">[1.5.0dev2] - 2026-03-28 <em>(リリース済みバージョン — v1.5.0 に統合)</em> <a class="header-anchor" href="#_1-5-0dev2-2026-03-28-リリース済みバージョン-—-v1-5-0-に統合" aria-label="Permalink to &quot;[1.5.0dev2] - 2026-03-28 *(リリース済みバージョン — v1.5.0 に統合)*&quot;">​</a></h3><h4 id="パッケージングとide支援の改善-1" tabindex="-1">パッケージングとIDE支援の改善 <a class="header-anchor" href="#パッケージングとide支援の改善-1" aria-label="Permalink to &quot;パッケージングとIDE支援の改善&quot;">​</a></h4><ul><li><strong>[High] PEP 561 準拠と型補完の修正</strong>: <ul><li><code>pyproject.toml</code> の <code>tool.setuptools</code> 設定を標準的な <code>src-layout</code> 用に刷新。これまで PyPI 配布版で <code>import nanasqlite</code> した際に型補完（IntelliSense）が効かなかった問題を修正しました。</li><li><code>include-package-data = true</code> を有効化し、<code>MANIFEST.in</code> を追加することで、ビルドされたパッケージ (.whl, sdist) に確実に <code>py.typed</code> ファイルが含まれるようにしました。</li><li>これにより、VS Code (Pylance) や PyCharm 等の主要な IDE で、インストール直後から <code>NanaSQLite</code> や <code>PydanticHook</code> などの完全な型補完が利用可能になりました。</li></ul></li></ul><h3 id="_1-5-0dev1-2026-03-28" tabindex="-1">[1.5.0dev1] - 2026-03-28 <a class="header-anchor" href="#_1-5-0dev1-2026-03-28" aria-label="Permalink to &quot;[1.5.0dev1] - 2026-03-28&quot;">​</a></h3><h4 id="リリース品質監査-release-audit-による改善-1" tabindex="-1">リリース品質監査 (Release Audit) による改善 <a class="header-anchor" href="#リリース品質監査-release-audit-による改善-1" aria-label="Permalink to &quot;リリース品質監査 (Release Audit) による改善&quot;">​</a></h4><ul><li><strong>[Critical] BUG-01</strong>: <code>batch_update</code>, <code>batch_update_partial</code>, <code>batch_delete</code> メソッドにおいて V2 モードをバイパスして直接 DB を書き換えていた不具合を修正。V2 エンジンのステージングバッファを経由するようにルーティングし、データの整合性と順序を保証しました。</li><li><strong>[Critical] BUG-02</strong>: <code>clear()</code> および <code>load_all()</code> メソッドにおいて、V2 エンジンの <code>flush()</code> が完了する前に DB 操作が実行され、古いデータが再挿入される「幽霊書き込み（Ghost Re-inserts）」が発生する問題を修正。<code>flush(wait=True)</code> による同期的待機を導入しました。</li><li><strong>[High] QUAL-01</strong>: <code>AsyncNanaSQLite.add_hook()</code> の実装を整理。ベース DB 初期化前後のフック登録処理を堅牢化し、非同期実行時の安定性を向上させました。</li><li><strong>[Non-Breaking] API 拡張</strong>: <code>flush()</code> (同期) および <code>aflush()</code> (非同期) に <code>wait</code> 引数を追加。バックグラウンド処理の完了を待機できるようになりました。</li><li><strong>[High] Python 3.9 互換性の完全復旧</strong>: <ul><li>全てのソースファイルに <code>from __future__ import annotations</code> を追加し、Python 3.10+ の <code>|</code> (Union) 演算子を型ヒントで使用していても Python 3.9 で動作するように修正しました。</li><li><code>compat.py</code> に <code>EllipsisType</code> の互換レイヤーを導入し、Python 3.9 環境での <code>mypy</code> チェックと実行時の型検証の安定性を向上させました。</li><li><code>pyproject.toml</code> の <code>mypy</code> 設定を <code>3.9</code> に更新し、継続的な互換性を保証しました。</li></ul></li></ul><h4 id="新機能-ultimate-hooks-汎用フック-制約アーキテクチャ-1" tabindex="-1">新機能: Ultimate Hooks (汎用フック＆制約アーキテクチャ) <a class="header-anchor" href="#新機能-ultimate-hooks-汎用フック-制約アーキテクチャ-1" aria-label="Permalink to &quot;新機能: Ultimate Hooks (汎用フック＆制約アーキテクチャ)&quot;">​</a></h4><ul><li><strong>強力なフック機構の導入</strong>: <ul><li><code>NanaHook</code> プロトコルを新設し、<code>before_write</code>, <code>after_read</code>, <code>before_delete</code> の3つのライフサイクルイベントをフック可能にしました。</li><li>カスタムフックを自作することで、データの検証、暗号化の拡張、ロギング、他システムへの通知などを自由に実装できます。</li></ul></li><li><strong>標準制約（Standard Constraints）の組み込み</strong>: <ul><li><code>CheckHook</code>: SQLite の <code>CHECK</code> 制約のような関数ベースの検証を提供。</li><li><code>UniqueHook</code>: 指定したキー（またはフィールド）の値の一意性を保証。</li><li><code>ForeignKeyHook</code>: 他の <code>NanaSQLite</code> テーブルのキーに対する参照整合性を保証。</li></ul></li><li><strong>外部ライブラリ統合の透過的サポート</strong>: <ul><li><code>ValidkitHook</code>: 従来の <code>validator</code> 引数と互換性を持ち、<code>validkit-py</code> による高性能バリデーションを提供。</li><li><code>PydanticHook</code>: <code>Pydantic</code> モデルを直接フックに登録することで、読み書き時の自動シリアライズ/デシリアライズおよび厳格な型検証を実現。</li></ul></li><li><strong>メソッドの拡張</strong>: <ul><li><code>NanaSQLite.add_hook()</code> および <code>AsyncNanaSQLite.add_hook()</code> を追加しました。</li></ul></li></ul><h4 id="アーキテクチャ強化と後方互換性-1" tabindex="-1">アーキテクチャ強化と後方互換性 <a class="header-anchor" href="#アーキテクチャ強化と後方互換性-1" aria-label="Permalink to &quot;アーキテクチャ強化と後方互換性&quot;">​</a></h4><ul><li>従来の <code>validator</code> パラメータは内部的に <code>ValidkitHook</code> へと自動変換されるようになり、後方互換性が100%維持されています。</li><li><code>batch_update</code>, <code>get</code>, <code>batch_get</code>, <code>setdefault</code>, <code>pop</code> など、あらゆるアクセス経路でフックが等しく適用されるように内部ロジックを統合・堅牢化しました。</li></ul><h3 id="_1-4-1-2026-03-27" tabindex="-1">[1.4.1] - 2026-03-27 <a class="header-anchor" href="#_1-4-1-2026-03-27" aria-label="Permalink to &quot;[1.4.1] - 2026-03-27&quot;">​</a></h3><h4 id="セキュリティ修正-2" tabindex="-1">セキュリティ修正 <a class="header-anchor" href="#セキュリティ修正-2" aria-label="Permalink to &quot;セキュリティ修正&quot;">​</a></h4><ul><li>QUAL-07 [High] 同期版 <code>NanaSQLite</code> クラスに V2 エンジンの管理メソッドを追加し、完全な機能パリティを実現しました。</li><li>CORE [Critical] <code>clear()</code>、<code>load_all()</code>、<code>restore()</code> メソッドにおける V2 エンジンの整合性を強化し、データの不整合や「幽霊書き込み」を防止しました。</li><li>SEC-01/02 [Critical] <code>column_type</code> バリデーションに ReDoS 対策を施したホワイトリスト方式を導入し、セキュリティを強化しました。</li><li>CONC-01/02 [High] V2 エンジンと <code>ExpiringDict</code> におけるマルチスレッド実行時のレースコンディションおよびデッドロックを修正しました。</li><li><strong>[Critical] PERF-02</strong>: <code>table()</code> メソッドで作成された子インスタンスが親の <code>V2Engine</code> を共有するように改善。これにより、テーブルごとにスレッドや <code>atexit</code> ハンドラが生成されるリソースリーク（およびプロセス終了時のハングアップ）を解消しました。</li><li><strong>[Critical] DEADLOCK-01</strong>: <code>V2Engine</code> において <code>StrictTask</code> の処理中にデッドロックが発生し、<code>pytest</code> 等の並列実行中にプロセスがハングアップする問題を修正しました。タスク処理のトランザクション分離と、<code>shutdown</code> 時の確実なイベント解放を実装しました。</li><li><strong>[Critical] MULTI-TENANT-01</strong>: <code>V2Engine</code> が単一のテーブル名に依存していた不具合を修正。複数のテーブルインスタンスが一つのエンジンを共有しても、データが混同されないマルチテナント（テーブル単位の分離）に対応しました。</li><li><strong>[High] QUAL-08</strong>: <code>V2Engine.shutdown()</code> の堅牢性を強化。二重実行の防止、<code>atexit</code> ハンドラの確実な解除、およびシャットダウン時のフラッシュ処理の安全性を向上させました。</li><li>QUAL-05 [Medium] V2 モードでの明示的な <code>begin_transaction()</code> 呼び出しに対するガードを追加し、バックグラウンドフラッシュとの衝突を防止しました。</li><li><strong>[Medium] SEC-02</strong>: <code>core.py</code> における <code>column_type</code> バリデーションの正規表現を脆弱性パターン（<code>[\\w ]*</code>）から安全なパターンに修正し、SonarQube が警告していた ReDoS（正規表現によるサービス拒否）の脆弱性を完全に解消しました。</li></ul><h4 id="バグ修正-3" tabindex="-1">バグ修正 <a class="header-anchor" href="#バグ修正-3" aria-label="Permalink to &quot;バグ修正&quot;">​</a></h4><ul><li><strong>[High] BUG-01</strong>: <code>upsert()</code> および <code>aupsert()</code> において、データ辞書を第1引数に渡しつつ <code>conflict_columns</code> を指定した場合に <code>AttributeError</code> が発生する問題を修正。解決済みの <code>target_data</code> のキーを参照するよう内部ロジックを改善しました。（1.4.1rc1）</li><li><strong>[High] Qual-02</strong>: <code>AsyncNanaSQLite</code> の初期化時において、複数の非同期タスクが同時にアクセスした場合に発生する可能性があった競合状態（Race Condition）を修正。<code>asyncio.Lock</code> を導入し、スレッドプールの二重初期化を防止しました。</li><li><code>AsyncNanaSQLite.table()</code> において、docstring の分断や引数伝搬の不備により発生していた構文エラーおよび初期化の不具合を修正しました。（1.4.1dev3）</li><li><code>AsyncNanaSQLite</code> の一部メソッドにおいて、機能適用時に重複して定義されていた箇所を整理しました。（1.4.1dev3）</li></ul><h4 id="最終監査-deep-audit-による重要修正" tabindex="-1">最終監査（Deep Audit）による重要修正 <a class="header-anchor" href="#最終監査-deep-audit-による重要修正" aria-label="Permalink to &quot;最終監査（Deep Audit）による重要修正&quot;">​</a></h4><ul><li><strong>[Critical] BUG-02</strong>: V2モードにおいて、書き込み直後に <code>get()</code> や <code>__getitem__</code> でデータを取得すると古い値が返る「不整合（Stale Read）」バグを修正。バックグラウンドのステージングバッファを優先的に参照するように改善しました。</li><li><strong>[Critical] QUAL-04</strong>: <code>AsyncNanaSQLite</code> の <code>__init__</code> 内で <code>asyncio.Lock()</code> を初期化していたため、イベントループ外でインスタンス化した際にエラーが発生する問題を修正。ロックを遅延初期化（Lazy Initialization）するように変更しました。</li><li><strong>[Critical] LOCK-01</strong>: <code>ExpiringDict</code> の TTL 失効処理（<code>on_expire</code>）が DB ロックを保持したまま呼び出され、通常の書き込み処理と競合してデッドロックが発生する問題を修正。コールバックをロックの外側で実行するように改善しました。</li><li><strong>[Critical] CONC-01</strong>: <code>NanaSQLite</code> の内部キャッシュ更新処理が DB ロックの外側で行われていたため、マルチスレッド環境（<code>AsyncNanaSQLite</code> 等）で <code>RuntimeError</code> やキャッシュ破損、TOCTOU 競合が発生する問題を修正。キャッシュ操作を DB ロックの保護下に移動しました。</li><li><strong>[Critical] CONC-02</strong>: V2モードで <code>table()</code> を使用して子インスタンスを作成した際、同じ SQLite 接続に対して複数のスレッドが同時にトランザクションを開始しようとしてクラッシュする問題を修正。親子の V2Engine 間で <code>shared_lock</code> を共有し、排他制御を強化しました。</li><li><strong>[Critical] ASYNC-01</strong>: <code>AsyncNanaSQLite</code> において V2 モード用のメソッド（<code>aflush</code>, <code>aget_dlq</code> 等）が未実装であった問題を修正。同期版と同等のすべての管理機能を非同期 API として追加しました。</li><li><strong>[High] QUAL-07</strong>: 同期版 <code>NanaSQLite</code> にも V2 管理メソッドを追加し、非同期版との完全な機能パリティを実現。</li><li><strong>[High] QUAL-05</strong>: V2モードにおいて <code>begin_transaction()</code> 等の明示的なトランザクション操作を行うと V2 エンジンのバックグラウンド処理と衝突するため、V2モード時は明示的なトランザクションを禁止（例外送出）するようにガードを追加しました。</li><li><strong>[High] QUAL-06</strong>: <code>AsyncNanaSQLite.table()</code> において <code>v2_enable_metrics</code> 設定が子インスタンスに継承されない不具合を修正しました。</li><li><strong>[Medium] SEC-01 (強化)</strong>: <code>create_table()</code> のカラム型バリデーションをブラックリスト方式からホワイトリスト方式（正規表現による記号制限）へ移行し、検知パターンを強化しました。</li></ul><h4 id="パフォーマンス改善-4" tabindex="-1">パフォーマンス改善 <a class="header-anchor" href="#パフォーマンス改善-4" aria-label="Permalink to &quot;パフォーマンス改善&quot;">​</a></h4><ul><li><strong>[Low] PERF-01</strong>: LRU および TTL キャッシュ戦略において、データベースに存在しないキーの検索結果を記憶する「ネガティブキャッシュ」を導入し、繰り返しアクセス時の I/O 負荷を削減しました。（同時に、本機能によってセンチネルが混入する破壊的バグを早期発見し修正済みです）（1.4.1rc1）</li></ul><h4 id="コード品質改善-2" tabindex="-1">コード品質改善 <a class="header-anchor" href="#コード品質改善-2" aria-label="Permalink to &quot;コード品質改善&quot;">​</a></h4><ul><li><strong>[Low] QUAL-01</strong>: <code>ExpiringDict</code> のスケジューラスレッド停止処理を改善し、インスタンス破棄時やクリア時のクリーンアップをより堅牢にしました。（1.4.1rc1）</li><li><strong>[Low] QUAL-03</strong>: ソースコード内のマジックリテラル（<code>&quot;BEGIN IMMEDIATE&quot;</code> 等）の共通定数化を行い、保守性を向上させました。</li><li><strong>[Low] CI-01</strong>: SonarQube Cloud の「Quality Gate」における誤検知（ドキュメントやスクリプトがカバレッジに含まれる問題）を解消し、認知複雑度などの非本質的な警告を抑制する設定を導入しました。</li><li><strong>[Low] QUAL-09</strong>: <code>utils.py</code> の <code>list(dict.keys())</code> を <code>list(dict)</code> に変更し、不要な <code>.keys()</code> 呼び出しを削除しました（SonarCloud指摘対応）。</li><li><strong>[Low] QUAL-10 (新機能)</strong>: <code>V2Config</code> データクラスを追加し、v2関連パラメータ（<code>flush_mode</code>, <code>flush_interval</code>, <code>flush_count</code>, <code>chunk_size</code>, <code>enable_metrics</code>）をひとまとめにして渡せるようにしました。既存の個別引数は後方互換のためすべて維持されます。SonarCloud の「パラメータが多すぎる（brain-overload）」警告への対応です。<div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> nanasqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NanaSQLite, V2Config</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cfg </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> V2Config(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">flush_mode</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;time&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">flush_interval</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">enable_metrics</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">True</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NanaSQLite(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mydata.db&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">v2_mode</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">True</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">v2_config</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cfg)</span></span></code></pre></div></li><li><strong>[Low] CI-02</strong>: <code>bench-rpi.yml</code> において、<code>docker run</code> 実行前に <code>docker rm -f</code> を追加し、キャンセル後の再実行時にコンテナ名が競合するエラー（<code>&quot;Conflict. The container name is already in use&quot;</code>）を解消しました。</li></ul><h4 id="新機能-v2エンジンの利便性と観測性の向上-オプトイン" tabindex="-1">新機能: V2エンジンの利便性と観測性の向上 (オプトイン) <a class="header-anchor" href="#新機能-v2エンジンの利便性と観測性の向上-オプトイン" aria-label="Permalink to &quot;新機能: V2エンジンの利便性と観測性の向上 (オプトイン)&quot;">​</a></h4><ul><li><strong>デッドレターキュー (DLQ) の可視化</strong>: <ul><li><code>get_dlq()</code>, <code>retry_dlq()</code>, <code>clear_dlq()</code> メソッドを同期・非同期（<code>a*</code>）両方に追加しました。</li><li>バックグラウンドで発生したエラー内容を直接確認し、必要に応じて手動でリトライや消去が可能です。</li></ul></li><li><strong>メトリクス収集機能</strong>: <ul><li><code>v2_enable_metrics=True</code> を指定することで、エンジンの詳細な統計情報を収集可能になりました。</li><li><code>get_v2_metrics()</code> により、総フラッシュ件数、処理時間、DLQ発生数などのメトリクスを取得できます。</li></ul></li><li><strong>設定の継承</strong>: <ul><li><code>table()</code> メソッドで子インスタンスを作成する際、<code>v2_enable_metrics</code> などの V2 固有設定が正しく引き継がれるようになりました。</li></ul></li></ul><h4 id="ドキュメント" tabindex="-1">ドキュメント <a class="header-anchor" href="#ドキュメント" aria-label="Permalink to &quot;ドキュメント&quot;">​</a></h4><ul><li><strong>APIリファレンス自動生成の刷新</strong>: <code>scripts/gen_api_docs.py</code> を大幅に改修し、VitePress のコールアウトやテーブルを活用した、より美しく使いやすい API ドキュメントの自動生成を実現しました。</li><li><strong>全ドキュメントのモダン化</strong>: 既存の Markdown ドキュメント内の太字警告等を、VitePress 標準のカスタムコンテナ（<code>::: warning</code> 等）へ一括変換し、サイト全体のデザインを統一しました。</li></ul><h3 id="_1-4-0-2026-03-12" tabindex="-1">[1.4.0] - 2026-03-12 <a class="header-anchor" href="#_1-4-0-2026-03-12" aria-label="Permalink to &quot;[1.4.0] - 2026-03-12&quot;">​</a></h3><h4 id="セキュリティ修正-3" tabindex="-1">セキュリティ修正 <a class="header-anchor" href="#セキュリティ修正-3" aria-label="Permalink to &quot;セキュリティ修正&quot;">​</a></h4><ul><li><strong>[Critical] SEC-01</strong>: <code>create_table()</code> のカラム型に対するSQLインジェクション脆弱性を修正。APSW はセミコロン区切りの複数文を一度に実行するため、カラム型定義を通じて任意のSQLを実行可能でした。セミコロン (<code>;</code>)、ラインコメント (<code>--</code>)、ブロックコメント (<code>/*</code>) を含む文字列を拒否するバリデーションを追加しました。</li></ul><h4 id="バグ修正-4" tabindex="-1">バグ修正 <a class="header-anchor" href="#バグ修正-4" aria-label="Permalink to &quot;バグ修正&quot;">​</a></h4><ul><li><strong>[High] BUG-01</strong>: V2Engine の <code>_process_strict_queue()</code> で <code>on_success</code> コールバックがトランザクション COMMIT 前に呼ばれ、後続タスク失敗時のロールバックで不整合が発生する問題を修正。コールバックを COMMIT 成功後に遅延実行するよう変更しました。</li><li><strong>[Medium] BUG-02</strong>: <code>AsyncNanaSQLite.table()</code> で子インスタンスに <code>_v2_mode</code>, <code>_cache_strategy</code>, <code>_encryption_key</code> 等の属性が設定されず <code>AttributeError</code> が発生する問題を修正。親インスタンスの全設定を正しく継承するよう変更しました。</li><li><strong>[Medium] BUG-03</strong>: v2モードで <code>execute()</code> 経由の SELECT/PRAGMA/EXPLAIN クエリが常に空結果を返す問題を修正。読み取りクエリをバックグラウンドキューからバイパスして直接実行するよう変更しました。</li></ul><h4 id="コード品質改善-3" tabindex="-1">コード品質改善 <a class="header-anchor" href="#コード品質改善-3" aria-label="Permalink to &quot;コード品質改善&quot;">​</a></h4><ul><li><strong>[Low] BUG-04</strong>: <code>async_core.py</code> の <code>_shared_query_impl()</code> 内で重複していたエイリアス抽出ロジックを <code>NanaSQLite._extract_column_aliases()</code> の呼び出しに置き換えました。</li><li><strong>[Low] QUAL-01</strong>: <code>update()</code> メソッドの型アノテーションを <code>dict</code> から <code>dict | None</code> に修正しました。</li></ul><h3 id="_1-4-0dev2-2026-03-12" tabindex="-1">[1.4.0dev2] - 2026-03-12 <a class="header-anchor" href="#_1-4-0dev2-2026-03-12" aria-label="Permalink to &quot;[1.4.0dev2] - 2026-03-12&quot;">​</a></h3><h4 id="改善-非同期-api-の完全化" tabindex="-1">改善: 非同期 API の完全化 <a class="header-anchor" href="#改善-非同期-api-の完全化" aria-label="Permalink to &quot;改善: 非同期 API の完全化&quot;">​</a></h4><ul><li><code>AsyncNanaSQLite</code> において、同期版と同等の全主要メソッドを非同期版（<code>abackup</code>, <code>arestore</code>, <code>apragma</code>, <code>aget_table_schema</code>, <code>alist_indexes</code>, <code>aalter_table_add_column</code>, <code>aupsert</code>, <code>aget_dlq</code>, <code>aretry_dlq</code> 等）として実装・公開しました。</li></ul><h4 id="変更-upsert-メソッドの統合と強化" tabindex="-1">変更: upsert() メソッドの統合と強化 <a class="header-anchor" href="#変更-upsert-メソッドの統合と強化" aria-label="Permalink to &quot;変更: upsert() メソッドの統合と強化&quot;">​</a></h4><ul><li><code>upsert()</code> メソッドのシグネチャを統合し、<code>(table_name, data_dict, conflict_columns)</code> パターンと <code>(key, value)</code> パターンの両方を単一のメソッドでサポートするように強化しました。</li><li>v2 モード有効時に <code>(key, value)</code> パターンで呼び出すと、内部的にバックグラウンドキューへルーティングされます。</li></ul><h4 id="テスト-ベンチマーク・カバレッジの拡充" tabindex="-1">テスト: ベンチマーク・カバレッジの拡充 <a class="header-anchor" href="#テスト-ベンチマーク・カバレッジの拡充" aria-label="Permalink to &quot;テスト: ベンチマーク・カバレッジの拡充&quot;">​</a></h4><ul><li><code>pytest-benchmark</code> による計測対象を 158 から <strong>177</strong> に拡大。</li><li>これまで未カバーだった <code>backup</code>, <code>restore</code>, <code>pragma</code>, <code>DDL (alter table/index)</code>, <code>export/import</code> 等の主要全操作を計測対象に追加しました。</li><li>非同期ベンチマーク (<code>tests/test_async_benchmark.py</code>) を大幅に強化。</li></ul><h4 id="修正" tabindex="-1">修正 <a class="header-anchor" href="#修正" aria-label="Permalink to &quot;修正&quot;">​</a></h4><ul><li><code>get_table_schema</code> メソッドが <code>table</code> プロパティが存在しない場合にエラーになる不具合を修正し、<code>table_name</code> 引数を省略可能（デフォルトで現在のテーブルを使用）に変更しました。</li><li>プロジェクト全体の <code>ruff</code> lint エラー（31件）および <code>mypy</code> 型チェックエラーを解消。</li></ul><h3 id="_1-4-0dev1-2026-03-12" tabindex="-1">[1.4.0dev1] - 2026-03-12 <a class="header-anchor" href="#_1-4-0dev1-2026-03-12" aria-label="Permalink to &quot;[1.4.0dev1] - 2026-03-12&quot;">​</a></h3><h4 id="新機能-v2-アーキテクチャ-オプション" tabindex="-1">新機能: v2 アーキテクチャ (オプション) <a class="header-anchor" href="#新機能-v2-アーキテクチャ-オプション" aria-label="Permalink to &quot;新機能: v2 アーキテクチャ (オプション)&quot;">​</a></h4><ul><li><strong>ノンブロッキング・バックグラウンド永続化</strong>: <ul><li><code>NanaSQLite(db_path, v2_mode=True)</code> を指定することで、v2アーキテクチャが有効になります。</li><li>すべての書き込み操作（KVS操作およびSQL実行）が一時的にメモリ上のバッファまたはキューに格納され、バックグラウンドスレッドで非同期にSQLiteへフラッシュされます。</li><li>これにより、<strong>書き込みによるメインスレッドのI/Oブロックが完全にゼロ</strong>になり、書き込みレイテンシが劇的に改善します。</li><li>読み込みレイテンシは従来通り（メモリキャッシュから直接取得するため）ゼロコストです。</li><li><strong>フラッシュモード</strong>: <code>flush_mode</code> パラメータで最適なタイミング（<code>immediate</code>, <code>count</code>, <code>time</code>, <code>manual</code>）を選択できます。</li><li><strong>デッドレターキュー (DLQ)</strong>: バックグラウンドでのSQL実行失敗時に、問題のあるタスクだけを隔離し、他のデータ永続化を継続・保護します。<code>get_dlq()</code> で内容確認、<code>retry_dlq()</code> で再試行が可能です。</li><li><strong>チャンク処理</strong>: 大量データの書き込み時にSQLiteのロックを長時間占有しないよう、バッチを分割（デフォルト 1000件ごと）して少しずつ書き込みます。</li><li><strong>注意</strong>: v2アーキテクチャは「単一プロセス」システム専用です。マルチプロセス環境（FastAPI/Gunicornの複数ワーカーなど）ではデータ破損の原因となるため警告が出力されます。</li></ul></li></ul><h4 id="変更" tabindex="-1">変更 <a class="header-anchor" href="#変更" aria-label="Permalink to &quot;変更&quot;">​</a></h4><ul><li><code>NanaSQLite</code> および <code>AsyncNanaSQLite</code> の <code>__init__</code> に <code>v2_mode</code>, <code>flush_mode</code>, <code>flush_interval</code>, <code>flush_count</code>, <code>v2_chunk_size</code> パラメータを追加。</li><li>手動フラッシュ用の <code>flush()</code> (同期) および <code>aflush()</code> (非同期) メソッドを追加。</li><li><code>V2Engine</code> に DLQ 管理用の <code>get_dlq()</code>, <code>retry_dlq()</code> メソッドを追加。</li></ul><h4 id="修正-1" tabindex="-1">修正 <a class="header-anchor" href="#修正-1" aria-label="Permalink to &quot;修正&quot;">​</a></h4><ul><li>v2 エンジンにおけるデッドレターキュー (DLQ) への同時アクセスによる競合状態 (Race Condition) を修正。</li><li>v2 エンジンにおいて Staging Buffer が空の場合に Strict Queue が処理されない不具合を修正。</li></ul><h3 id="_1-3-4-2026-03-10" tabindex="-1">[1.3.4] - 2026-03-10 <a class="header-anchor" href="#_1-3-4-2026-03-10" aria-label="Permalink to &quot;[1.3.4] - 2026-03-10&quot;">​</a></h3><h4 id="セキュリティ修正-4" tabindex="-1">セキュリティ修正 <a class="header-anchor" href="#セキュリティ修正-4" aria-label="Permalink to &quot;セキュリティ修正&quot;">​</a></h4><ul><li><strong>SEC-01 [High]</strong>: <code>alter_table_add_column()</code> の <code>column_type</code> バリデーションをブラックリスト方式からホワイトリスト正規表現に変更。<code>TEXT; DROP TABLE</code> のようなインジェクションペイロードを確実にブロック。</li><li><strong>SEC-02 [High]</strong>: <code>sanitize_sql_for_function_scan()</code> を修正し、ダブルクォート付き SQL 識別子の内容を保持するよう変更。<code>&quot;LOAD_EXTENSION&quot;()</code> のようなクォート付き関数名バイパスを <code>_validate_expression()</code> が正しく検出可能に。</li></ul><h4 id="バグ修正-5" tabindex="-1">バグ修正 <a class="header-anchor" href="#バグ修正-5" aria-label="Permalink to &quot;バグ修正&quot;">​</a></h4><ul><li><strong>BUG-01 [Critical]</strong>: <code>items()</code> メソッドに <code>_check_connection()</code> チェックを追加。クローズ済みインスタンスで呼び出した際に APSW 低レベル例外ではなく <code>NanaSQLiteClosedError</code> が発生するよう修正。</li><li><strong>BUG-02 [High]</strong>: AEAD 暗号化有効時に非 bytes 値を受け取った場合、サイレントに平文 JSON フォールバックするのではなく警告ログを出力するよう変更。</li><li><strong>BUG-03 [High]</strong>: AEAD 復号前に nonce+認証タグを含む最小長の検証（≥28 バイト = nonce 12 + auth tag 16）を追加。短すぎるデータに対して明確な <code>NanaSQLiteDatabaseError</code> を送出。InvalidTag など低レベル例外も同エラーにラップ。</li><li><strong>BUG-04 [High]</strong>: <code>AsyncNanaSQLite.acontains()</code> の冗長な二重 <code>_ensure_initialized()</code> 呼び出しを削除。</li><li><strong>BUG-05 [Medium]</strong>: 非同期 <code>_shared_query_impl()</code> に <code>offset</code> パラメータの型・非負チェックを追加。</li><li><strong>BUG-06 [Medium]</strong>: <code>async_core.py</code> の <code>parameters: tuple = None</code> を <code>tuple | None = None</code> に修正（mypy strict 対応）。</li><li><strong>BUG-07 [Medium]</strong>: <code>ExpiringDict</code> スケジューラが 1 反復で期限切れキーをすべて処理するよう改善（従来は 1 キーずつ）。</li><li><strong>BUG-09 [Medium]</strong>: <code>batch_get()</code> が値 <code>None</code> を明示的に格納したキーを結果に含めるよう修正。</li><li><strong>BUG-10 [Low]</strong>: <code>_sanitize_identifier()</code> でコンパイル済み <code>IDENTIFIER_PATTERN</code> を再利用。</li><li><strong>BUG-12 [Low]</strong>: <code>NanaSQLiteDatabaseError.__init__</code> の <code>original_error</code> 型アノテーションを <code>Exception | None</code> に修正。</li></ul><h4 id="パフォーマンス改善-5" tabindex="-1">パフォーマンス改善 <a class="header-anchor" href="#パフォーマンス改善-5" aria-label="Permalink to &quot;パフォーマンス改善&quot;">​</a></h4><ul><li><strong>PERF-03 [Medium]</strong>: カラム名エイリアス抽出ロジックを <code>_extract_column_aliases()</code> ヘルパーに共通化（3 箇所の重複排除）。</li></ul><h4 id="コード品質改善-4" tabindex="-1">コード品質改善 <a class="header-anchor" href="#コード品質改善-4" aria-label="Permalink to &quot;コード品質改善&quot;">​</a></h4><ul><li><strong>QUAL-01 [Medium]</strong>: <code>_get_all_keys_from_db()</code> の戻り値型を <code>list[str]</code> に修正。</li><li><strong>QUAL-03 [Medium]</strong>: <code>query()</code> と <code>query_with_pagination()</code> 間のカラム名クォート除去ロジックを統一。</li></ul><h4 id="監査・テスト-1" tabindex="-1">監査・テスト <a class="header-anchor" href="#監査・テスト-1" aria-label="Permalink to &quot;監査・テスト&quot;">​</a></h4><ul><li>プレリリース監査レポート (<code>audit.md</code>) を追加 — 35 件の発見事項を文書化。</li><li>POC スクリプト 6 件を <code>etc/poc/</code> に追加。</li><li>POC 検証テスト 20 件を <code>tests/test_audit_poc.py</code> に追加。</li><li><code>audit_prompt.md</code> を 6 フェーズ構成に改正（監査 → POC → パッチ → pytest → CI 検証 → リリース準備）。</li></ul><h3 id="_1-3-4rc4-2026-03-08" tabindex="-1">[1.3.4rc4] - 2026-03-08 <a class="header-anchor" href="#_1-3-4rc4-2026-03-08" aria-label="Permalink to &quot;[1.3.4rc4] - 2026-03-08&quot;">​</a></h3><h4 id="ci-修正" tabindex="-1">CI 修正 <a class="header-anchor" href="#ci-修正" aria-label="Permalink to &quot;CI 修正&quot;">​</a></h4><ul><li><strong>provenance ジョブの権限を最小権限に変更</strong> (PR <a href="https://github.com/disnana/NanaSQLite/pull/127" target="_blank" rel="noreferrer">#127</a>): <ul><li><code>provenance</code> ジョブの <code>contents: write</code> を <code>contents: read</code> に降格。<code>upload-assets</code> を使わないため <code>write</code> 権限は不要だった。</li><li>無効だった <code>upload-assets: true</code> を削除（タグトリガーのないワークフローでは常にスキップされていたデッドコード）。</li><li>プロベナンスの GitHub Release への添付は <code>release</code> ジョブが引き続き担当。</li><li>CI アノテーション（<code>go.sum not found</code> ワーニング・PyPI アテステーション通知）の原因をコメントで説明し、誤解を防止。</li><li><code>CHANGELOG.md</code> を main ブランチの最新版に同期。</li></ul></li></ul><h3 id="_1-3-4rc3-2026-03-08" tabindex="-1">[1.3.4rc3] - 2026-03-08 <a class="header-anchor" href="#_1-3-4rc3-2026-03-08" aria-label="Permalink to &quot;[1.3.4rc3] - 2026-03-08&quot;">​</a></h3><h4 id="ci-修正-1" tabindex="-1">CI 修正 <a class="header-anchor" href="#ci-修正-1" aria-label="Permalink to &quot;CI 修正&quot;">​</a></h4><ul><li><strong>SLSA3 provenance リリースフローを復旧・安定化</strong> (PR <a href="https://github.com/disnana/NanaSQLite/pull/123" target="_blank" rel="noreferrer">#123</a>): <ul><li>GitHub Actions の provenance 検証ジョブに <code>actions: read</code> / <code>contents: read</code> 権限を追加。</li><li><code>provenance-name</code> 出力から期待する provenance ファイル名を明示的に組み立て、存在確認に失敗した場合は早期終了するよう改善。</li><li>GitHub Release へ添付する provenance アーティファクトをワイルドカードではなく生成済みファイル名で指定し、リリース時の取り違えを防止。</li></ul></li></ul><h3 id="_1-3-4rc2-2026-03-08" tabindex="-1">[1.3.4rc2] - 2026-03-08 <a class="header-anchor" href="#_1-3-4rc2-2026-03-08" aria-label="Permalink to &quot;[1.3.4rc2] - 2026-03-08&quot;">​</a></h3><h4 id="セキュリティ修正-5" tabindex="-1">セキュリティ修正 <a class="header-anchor" href="#セキュリティ修正-5" aria-label="Permalink to &quot;セキュリティ修正&quot;">​</a></h4><ul><li><strong>SQLインジェクション保護を実装</strong> (PR <a href="https://github.com/disnana/NanaSQLite/pull/121" target="_blank" rel="noreferrer">#121</a>, <a href="https://github.com/disnana/NanaSQLite/pull/122" target="_blank" rel="noreferrer">#122</a>): <ul><li>テーブル名を SQL クエリ内で直接展開していたため、細工されたテーブル名でインジェクションが可能でした。</li><li><code>self._safe_table</code> にサニタイズ済み（クォート済み）のテーブル名をキャッシュし、すべての SQL 実行箇所でこちらを使用するよう変更。</li><li><code>self._table</code> は従来どおり生の名前を保持し、<code>__repr__</code> や後方互換のために使用。</li><li>SECURITY.md を更新し脆弱性の経緯と修正内容を記載。</li><li>PoC スクリプト (<code>etc/poc/poc_sqli.py</code>, <code>etc/poc/poc_none.py</code>) を追加してリスクを文書化。</li></ul></li></ul><h4 id="バグ修正・コード品質改善" tabindex="-1">バグ修正・コード品質改善 <a class="header-anchor" href="#バグ修正・コード品質改善" aria-label="Permalink to &quot;バグ修正・コード品質改善&quot;">​</a></h4><ul><li><strong><code>_NOT_FOUND</code> センチネルを <code>get_fresh()</code> および <code>__contains__</code> に適用</strong> (PR <a href="https://github.com/disnana/NanaSQLite/pull/121" target="_blank" rel="noreferrer">#121</a>): <ul><li><code>get_fresh()</code> が DB ミス時に <code>None</code> を返すため、実際に <code>None</code> を格納したキーと区別できなかった問題を修正。</li><li><code>_NOT_FOUND = object()</code> センチネルを使用し、DB ミスと格納値 <code>None</code> を正確に識別できるよう改善。</li><li><code>__contains__</code> を軽量な実装に戻し、不要な DB 読み込みを削減。</li></ul></li></ul><h4 id="ci-修正-2" tabindex="-1">CI 修正 <a class="header-anchor" href="#ci-修正-2" aria-label="Permalink to &quot;CI 修正&quot;">​</a></h4><ul><li><strong>validkit-py の CI テストガードを修正</strong> (PR <a href="https://github.com/disnana/NanaSQLite/pull/119" target="_blank" rel="noreferrer">#119</a>): <ul><li>CI で <code>validation</code> エクストラをインストールするよう修正し、validkit 関連テストが正しく実行されるようになった。</li></ul></li></ul><h4 id="ドキュメント-1" tabindex="-1">ドキュメント <a class="header-anchor" href="#ドキュメント-1" aria-label="Permalink to &quot;ドキュメント&quot;">​</a></h4><ul><li><strong>validkit-py バリデーションガイドを追加</strong> (PR <a href="https://github.com/disnana/NanaSQLite/pull/117" target="_blank" rel="noreferrer">#117</a>): <ul><li>日英両方のドキュメントサイトに validkit-py の使い方・バリデーションガイドを追加。</li></ul></li><li><strong>ガイドのレッスン順序を整理</strong> (PR <a href="https://github.com/disnana/NanaSQLite/pull/116" target="_blank" rel="noreferrer">#116</a>): <ul><li>JA/EN サイトドキュメントのガイドレッスンを再整理・分類。</li></ul></li><li><strong>ドキュメントの不整合・リンク切れ・誤記を修正</strong> (PR <a href="https://github.com/disnana/NanaSQLite/pull/115" target="_blank" rel="noreferrer">#115</a>): <ul><li>英語・日本語ドキュメント間の不整合、壊れたリンク、誤った記述、および欠落していた文書を修正。</li></ul></li></ul><h3 id="_1-3-4rc1-2026-03-07" tabindex="-1">[1.3.4rc1] - 2026-03-07 <a class="header-anchor" href="#_1-3-4rc1-2026-03-07" aria-label="Permalink to &quot;[1.3.4rc1] - 2026-03-07&quot;">​</a></h3><h4 id="新機能" tabindex="-1">新機能 <a class="header-anchor" href="#新機能" aria-label="Permalink to &quot;新機能&quot;">​</a></h4><ul><li><strong><code>batch_update_partial()</code> メソッドを追加</strong>（同期・非同期）: <ul><li><code>validator</code> が設定されている場合にバッチ書き込みを「部分成功モード」で実行する新メソッド。</li><li>各エントリを個別にバリデーションし、成功したものだけ DB に書き込む。</li><li>失敗したエントリは <code>{key: エラーメッセージ}</code> の <code>dict</code> として返却し、例外は送出しない。</li><li><code>coerce=True</code> の場合は変換済みの値で書き込む。</li><li>既存の <code>batch_update()</code> はアトミック動作（全件成功 or 全件拒否）のまま維持。</li><li>非同期版は <code>AsyncNanaSQLite.abatch_update_partial()</code> として追加。</li></ul></li></ul><h4 id="バグ修正・コード品質改善-1" tabindex="-1">バグ修正・コード品質改善 <a class="header-anchor" href="#バグ修正・コード品質改善-1" aria-label="Permalink to &quot;バグ修正・コード品質改善&quot;">​</a></h4><ul><li><strong><code>core.py</code> mypy エラーを修正</strong>: <ul><li><code>_serialize()</code> の <code>json_str</code> が <code>HAS_ORJSON=False</code> パスで <code>str</code> 確定だが mypy が <code>str | None</code> と推論していたため <code>type: ignore</code> を付与。</li></ul></li><li><strong>examples の ruff 違反を修正</strong>: <ul><li><code>examples/test_examples.py</code>: import ソート（I001）、<code>assert False</code> → <code>raise AssertionError()</code>（B011）、クラス名を CapWords に変更（N801）。</li><li><code>examples/validkit_batch_demo.py</code>: import ソート（I001）。</li></ul></li></ul><h4 id="サンプル追加" tabindex="-1">サンプル追加 <a class="header-anchor" href="#サンプル追加" aria-label="Permalink to &quot;サンプル追加&quot;">​</a></h4><ul><li><strong><code>examples/validkit_batch_demo.py</code> を追加</strong>: <ul><li><code>batch_update()</code> のアトミック動作と <code>batch_update_partial()</code> の部分成功モードを実演。</li><li><code>coerce=True</code> との組み合わせ例を含む。</li></ul></li><li><strong><code>examples/test_examples.py</code> に validkit バッチ操作の検証を追加</strong>: <ul><li><code>batch_update()</code> のロールバック確認、<code>batch_update_partial()</code> の部分書き込み確認、<code>coerce=True</code> の変換確認。</li></ul></li></ul><h3 id="_1-3-4b3-2026-03-05" tabindex="-1">[1.3.4b3] - 2026-03-05 <a class="header-anchor" href="#_1-3-4b3-2026-03-05" aria-label="Permalink to &quot;[1.3.4b3] - 2026-03-05&quot;">​</a></h3><h4 id="バグ修正・安定性改善" tabindex="-1">バグ修正・安定性改善 <a class="header-anchor" href="#バグ修正・安定性改善" aria-label="Permalink to &quot;バグ修正・安定性改善&quot;">​</a></h4><ul><li><p><strong>Python 3.9 でのテスト不安定問題を修正</strong> (<code>tests/test_tdd_cycle_6.py</code>) (PR <a href="https://github.com/disnana/NanaSQLite/pull/113" target="_blank" rel="noreferrer">#113</a>):</p><ul><li><code>test_ellipsis_type_is_available</code> は <code>types.EllipsisType</code>（Python 3.10 で追加）の有無を確認するテストですが、 Python 3.9 環境では無条件に失敗していました。</li><li><code>@pytest.mark.skipif(sys.version_info &lt; (3, 10), ...)</code> デコレータを追加し、Python 3.9 では このテストをスキップするよう修正。Python 3.10 以降では引き続き実行されます。</li><li><code>from __future__ import annotations</code> が有効なため、<code>types.EllipsisType</code> を使った型注釈は ランタイムに評価されず、Python 3.9 でも本体コードは正常に動作します（テストのみの問題でした）。</li><li>ライブラリの動作・公開 API への影響はありません。</li></ul></li><li><p><strong><code>table()</code> のキャッシュ設定継承を修正</strong> (PR <a href="https://github.com/disnana/NanaSQLite/pull/112" target="_blank" rel="noreferrer">#112</a>):</p><ul><li><code>table()</code> で子インスタンスを生成する際、<code>cache_ttl</code> / <code>cache_persistence_ttl</code> が親から引き継がれず、 TTL キャッシュ戦略を使用している場合に <code>ValueError</code> が発生する問題を修正。</li><li><code>_cache_strategy_raw</code> / <code>_cache_size_raw</code> / <code>_cache_ttl_raw</code> / <code>_cache_persistence_ttl_raw</code> を内部に保持し、 <code>table()</code> が全キャッシュ設定を正しく継承するよう修正。</li></ul></li><li><p><strong><code>AsyncNanaSQLite</code> での validkit-py 未インストール時 <code>ImportError</code> の即時送出</strong> (PR <a href="https://github.com/disnana/NanaSQLite/pull/112" target="_blank" rel="noreferrer">#112</a>):</p><ul><li>従来は操作実行時まで <code>ImportError</code> が遅延されていたが、<code>AsyncNanaSQLite.__init__</code> で <code>validator</code> を指定した時点で 即座に送出するよう修正（<code>NanaSQLite</code> との挙動を統一）。</li><li><code>HAS_VALIDKIT</code> フラグを <code>async_core.py</code> に追加。</li></ul></li><li><p><strong>例外の絞り込み</strong> (<code>core.py</code>):</p><ul><li>オプション依存（orjson / validkit-py）のインポートで <code>except Exception:</code> を使用していた箇所を <code>except ImportError:</code> に変更。</li></ul></li><li><p><strong>型アノテーション修正</strong>:</p><ul><li><code>table()</code> の <code>cache_strategy</code> 引数の <code>Literal</code> 型に <code>&quot;ttl&quot;</code> を追加。</li><li><code>_UNSET</code> センチネルの型注釈を <code>types.EllipsisType</code> に変更し、型安全性を向上。</li></ul></li><li><p><strong>mypy 設定更新</strong> (<code>pyproject.toml</code>):</p><ul><li><code>python_version</code> を <code>3.9</code> → <code>3.10</code> に更新し、<code>types.EllipsisType</code> を型チェック時に認識させるよう修正。</li></ul></li></ul><h4 id="api-ドキュメント修正-pr-112" tabindex="-1">API ドキュメント修正 (PR <a href="https://github.com/disnana/NanaSQLite/pull/112" target="_blank" rel="noreferrer">#112</a>) <a class="header-anchor" href="#api-ドキュメント修正-pr-112" aria-label="Permalink to &quot;API ドキュメント修正 (PR [#112](https://github.com/disnana/NanaSQLite/pull/112))&quot;">​</a></h4><ul><li><code>NanaSQLite.table()</code> および <code>AsyncNanaSQLite.table()</code> の API ドキュメント（日・英）で、 <code>validator</code> / <code>coerce</code> の既定値が <code>= ...</code>（親から継承）であることを明記。</li></ul><h4 id="テスト・品質改善-pr-112" tabindex="-1">テスト・品質改善 (PR <a href="https://github.com/disnana/NanaSQLite/pull/112" target="_blank" rel="noreferrer">#112</a>) <a class="header-anchor" href="#テスト・品質改善-pr-112" aria-label="Permalink to &quot;テスト・品質改善 (PR [#112](https://github.com/disnana/NanaSQLite/pull/112))&quot;">​</a></h4><ul><li><strong>包括的テストスイートを追加</strong>: <ul><li><code>tests/test_table_inheritance_comprehensive.py</code>: <code>table()</code> の全継承パターンを 75 ケースで検証。</li><li><code>tests/test_validkit_integration.py</code>: validkit-py 統合テスト（同期・非同期）。</li><li><code>tests/test_tdd_review_fixes.py</code>: レビューコメント対応の検証テスト。</li><li><code>tests/test_tdd_cycle_2.py</code> 〜 <code>tests/test_tdd_cycle_10.py</code>: TDD サイクルごとの回帰テスト。</li></ul></li><li><strong>validkit インストール確認の方法を改善</strong>: <ul><li><code>importlib.util.find_spec</code> から <code>try/except import</code> 方式に変更し、破損インストールも正しく検出。</li></ul></li></ul><h3 id="_1-3-4b2-2026-03-04" tabindex="-1">[1.3.4b2] - 2026-03-04 <a class="header-anchor" href="#_1-3-4b2-2026-03-04" aria-label="Permalink to &quot;[1.3.4b2] - 2026-03-04&quot;">​</a></h3><h4 id="新機能-1" tabindex="-1">新機能 <a class="header-anchor" href="#新機能-1" aria-label="Permalink to &quot;新機能&quot;">​</a></h4><ul><li><p><strong><code>validator</code> パラメータの追加（オプション依存: validkit-py）</strong>:</p><ul><li><code>NanaSQLite.__init__</code> および <code>AsyncNanaSQLite.__init__</code> に <code>validator</code> パラメータを追加。</li><li>validkit-py のスキーマ（辞書または <code>Schema</code> オブジェクト）を渡すと、値の書き込み時に自動バリデーションを実行します。</li><li>スキーマ違反時は <code>NanaSQLiteValidationError</code> を送出。</li><li>validkit-py をインストールせずに <code>validator</code> を指定した場合は <code>ImportError</code> を送出し、インストール手順を案内します。</li><li><code>pip install nanasqlite[validation]</code> でインストール可能。</li><li><code>HAS_VALIDKIT</code> フラグを <code>nanasqlite</code> パッケージ（および <code>core</code> モジュール）から公開。</li></ul></li><li><p><strong><code>table()</code> の <code>validator</code> 引数対応</strong>:</p><ul><li><code>NanaSQLite.table()</code> および <code>AsyncNanaSQLite.table()</code> に <code>validator</code> パラメータを追加。</li><li>テーブルごとに異なるスキーマを適用可能。</li><li><code>validator</code> を省略した場合は親インスタンスのスキーマを自動継承。</li></ul></li><li><p><strong><code>coerce</code> パラメータの追加（自動変換オプション）</strong>:</p><ul><li><code>NanaSQLite.__init__</code>、<code>NanaSQLite.table()</code>、<code>AsyncNanaSQLite.__init__</code>、<code>AsyncNanaSQLite.table()</code> に <code>coerce: bool = False</code> パラメータを追加。</li><li><code>True</code> を指定すると、validkit-py のバリデーション後に変換済みの値（例: <code>&quot;42&quot;</code> → <code>42</code>）をDBに保存します。</li><li><strong>注意</strong>: 自動変換を機能させるには、スキーマの各フィールドバリデーターにも <code>.coerce()</code> を呼び出す必要があります（例: <code>v.int().coerce()</code>）。フィールドに <code>.coerce()</code> がない場合、型が一致しない値はバリデーションエラーになります（NanaSQLite の <code>coerce=True</code> だけでは変換されません）。</li><li><code>validator</code> と組み合わせて使用します。<code>validator</code> が設定されていない場合は無効。</li><li><code>table()</code> で省略した場合は親インスタンスの設定を引き継ぐ。</li></ul></li><li><p><strong><code>batch_update()</code> バリデーション対応</strong>:</p><ul><li><code>validator</code> を設定している場合、<code>batch_update()</code> はすべての値を DB 書き込み前に一括バリデーションするようになりました。</li><li>1件でもスキーマ違反があった場合、何も書き込まれません（アトミックな失敗保証）。</li><li><code>coerce=True</code> を設定している場合、変換済みの値を一括書き込みします。</li></ul></li></ul><h4 id="バグ修正-6" tabindex="-1">バグ修正 <a class="header-anchor" href="#バグ修正-6" aria-label="Permalink to &quot;バグ修正&quot;">​</a></h4><ul><li><strong><code>table()</code> で <code>validator</code> が子インスタンスに引き継がれない問題を修正</strong>: <ul><li>b1 では <code>table()</code> で生成した子インスタンスに親の <code>_validator</code> が渡されておらず、 サブテーブルへの書き込み時にバリデーションが実行されませんでした。</li><li><code>AsyncNanaSQLite.table()</code> でも同様に <code>_validator</code> が <code>async_sub_db</code> に設定されていなかった問題を修正。</li></ul></li></ul><h3 id="_1-3-4b1-2026-03-04" tabindex="-1">[1.3.4b1] - 2026-03-04 <a class="header-anchor" href="#_1-3-4b1-2026-03-04" aria-label="Permalink to &quot;[1.3.4b1] - 2026-03-04&quot;">​</a></h3><h4 id="新機能-2" tabindex="-1">新機能 <a class="header-anchor" href="#新機能-2" aria-label="Permalink to &quot;新機能&quot;">​</a></h4><ul><li><p><strong><code>lock_timeout</code> パラメータの追加</strong> (P2-1):</p><ul><li><code>NanaSQLite.__init__</code> に <code>lock_timeout: float | None = None</code> パラメータを追加。</li><li>設定すると、ロック取得時に指定秒数以内に取得できない場合は <code>NanaSQLiteLockError</code> を送出。</li><li>デフォルト <code>None</code> は従来通り無制限待機。後方互換性への影響はありません。</li><li>内部に <code>_acquire_lock()</code> コンテキストマネージャを新設し、ユーザー操作に伴う排他制御ではロックタイムアウトが反映されます（一部の内部処理〈期限切れ削除など〉は従来通りブロッキング取得のままです）。</li></ul></li><li><p><strong><code>backup()</code> / <code>restore()</code> メソッドの追加</strong> (P2-3):</p><ul><li><code>NanaSQLite.backup(dest_path)</code>: APSW の SQLite オンラインバックアップ API を使用して、現在の DB を <code>dest_path</code> にバックアップします。</li><li><code>NanaSQLite.restore(src_path)</code>: <code>src_path</code> のバックアップファイルから DB を復元し、接続を再確立してキャッシュをクリアします。リストア時に WAL/SHM/journal サイドカーファイル（<code>-wal</code>/<code>-shm</code>/<code>-journal</code>）を明示的に削除し、stale な WAL 内容の再生による不整合を防止します。</li><li>両メソッドとも新規 public メソッドの追加のみ。後方互換性への影響はありません。</li></ul></li></ul><h4 id="スレッドセーフティ改善" tabindex="-1">スレッドセーフティ改善 <a class="header-anchor" href="#スレッドセーフティ改善" aria-label="Permalink to &quot;スレッドセーフティ改善&quot;">​</a></h4><ul><li><strong><code>table()</code> の子インスタンス生成をロック保護</strong>: <ul><li><code>table()</code> での子インスタンス生成〜<code>WeakSet</code> 追加を <code>_acquire_lock()</code> で保護。<code>restore()</code> の接続差し替えとの競合を防止し、子インスタンスが閉じた接続を参照するリスクを排除。</li></ul></li></ul><h4 id="バグ修正-7" tabindex="-1">バグ修正 <a class="header-anchor" href="#バグ修正-7" aria-label="Permalink to &quot;バグ修正&quot;">​</a></h4><ul><li><strong><code>__delitem__</code> に <code>_check_connection()</code> を追加</strong>: <ul><li><code>del db[key]</code> でクローズ済み接続を使用した際に <code>NanaSQLiteClosedError</code> を送出するよう修正。<code>__setitem__</code>・<code>pop()</code>・<code>clear()</code> と例外挙動を統一。</li></ul></li></ul><h3 id="_1-3-4b0-2026-03-04" tabindex="-1">[1.3.4b0] - 2026-03-04 <a class="header-anchor" href="#_1-3-4b0-2026-03-04" aria-label="Permalink to &quot;[1.3.4b0] - 2026-03-04&quot;">​</a></h3><h4 id="コード品質改善-5" tabindex="-1">コード品質改善 <a class="header-anchor" href="#コード品質改善-5" aria-label="Permalink to &quot;コード品質改善&quot;">​</a></h4><ul><li><strong>非同期プールクリーンアップのログレベル修正</strong>: <ul><li><code>AsyncNanaSQLite.close()</code> 内の読み取り専用プールドレイン処理で、<code>AttributeError</code> 発生時のログレベルを <code>ERROR</code> から <code>WARNING</code> に変更。</li><li>あわせてコメントの文言を「Programming error」から実態に即した「Unexpected AttributeError - log and continue cleanup for resilience」に修正。</li><li>ログ出力のみの変更であり、動作・後方互換性への影響はありません。</li></ul></li></ul><h4 id="ドキュメント・計画" tabindex="-1">ドキュメント・計画 <a class="header-anchor" href="#ドキュメント・計画" aria-label="Permalink to &quot;ドキュメント・計画&quot;">​</a></h4><ul><li><strong>v1.3.x 計画レビュードキュメントの追加</strong> (<code>etc/in_progress/v1.3.x_plan_review.md</code>): <ul><li><code>etc/</code> 配下の全計画書を横断的にレビューし、v1.3.x で実施すべき残タスクを整理・優先順位付け。</li><li>ロードマップ残項目（ロックタイムアウト、バリデーション基盤、バックアップ/リストア）の対応優先度を明記。</li><li>v1.3.4b0 〜 v1.4.0 のリリース計画案を記載。</li></ul></li><li><strong><code>etc/README.md</code> 更新</strong>: 新規レビュードキュメントを <code>in_progress/</code> 一覧に追記。</li><li><strong><code>etc/</code> ディレクトリの再編</strong>（PR <a href="https://github.com/disnana/NanaSQLite/pull/109" target="_blank" rel="noreferrer">#109</a>）: <ul><li><code>etc/</code> を実装状況別（<code>implemented/</code>・<code>in_progress/</code>・<code>planned/</code>）のサブディレクトリ構造に再編。フラットな <code>future_plans/</code> フォルダを廃止。</li><li>v1.3.0 キャッシュ機能（<code>ExpiringDict</code>・<code>UnboundedCache</code>・<code>TTLCache</code> 等）がすべて実装済みであることを確認。</li></ul></li></ul><h4 id="依存関係更新-docs-site-メンテナンス" tabindex="-1">依存関係更新（docs/site メンテナンス） <a class="header-anchor" href="#依存関係更新-docs-site-メンテナンス" aria-label="Permalink to &quot;依存関係更新（docs/site メンテナンス）&quot;">​</a></h4><ul><li><strong>docs/site 依存ライブラリの更新</strong>（Renovate）: <ul><li><code>autoprefixer</code> を v10.4.24 → v10.4.27 に更新。(<a href="https://github.com/disnana/NanaSQLite/pull/105" target="_blank" rel="noreferrer">#105</a>)</li><li><code>postcss</code> を v8.5.6 → v8.5.8 に更新。(<a href="https://github.com/disnana/NanaSQLite/pull/106" target="_blank" rel="noreferrer">#106</a>)</li><li><code>vue</code> を v3.5.27 → v3.5.29 に更新。(<a href="https://github.com/disnana/NanaSQLite/pull/107" target="_blank" rel="noreferrer">#107</a>)</li><li><code>tailwindcss</code> / <code>@tailwindcss/postcss</code> を v4.1.18 → v4.2.1 に更新。(<a href="https://github.com/disnana/NanaSQLite/pull/108" target="_blank" rel="noreferrer">#108</a>)</li></ul></li></ul><h3 id="_1-3-4dev0-2026-03-02" tabindex="-1">[1.3.4dev0] - 2026-03-02 <a class="header-anchor" href="#_1-3-4dev0-2026-03-02" aria-label="Permalink to &quot;[1.3.4dev0] - 2026-03-02&quot;">​</a></h3><h4 id="ci-開発環境" tabindex="-1">CI / 開発環境 <a class="header-anchor" href="#ci-開発環境" aria-label="Permalink to &quot;CI / 開発環境&quot;">​</a></h4><ul><li><strong>SLSA プロバナンスキャッシュ警告への対応・撤退</strong>: <ul><li><code>provenance / generator</code> ジョブが <code>go.sum</code> を探して <code>Restore cache failed</code> 警告を出力していたため、空の <code>go.sum</code> をリポジトリルートに追加（PR <a href="https://github.com/disnana/NanaSQLite/pull/103" target="_blank" rel="noreferrer">#103</a>）。</li><li>その後、<code>provenance / generator</code> ジョブは独立したランナーで実行されリポジトリをチェックアウトしないため、ファイルの有無に関係なく警告を解消できないことが判明。空の <code>go.sum</code> を削除（PR <a href="https://github.com/disnana/NanaSQLite/pull/104" target="_blank" rel="noreferrer">#104</a>）。</li></ul></li></ul><h4 id="その他" tabindex="-1">その他 <a class="header-anchor" href="#その他" aria-label="Permalink to &quot;その他&quot;">​</a></h4><ul><li>バージョンを <code>1.3.4dev0</code> に引き上げ（<code>1.3.3</code> リリース後の開発スナップショット）。</li></ul><h3 id="_1-3-3-2026-03-02" tabindex="-1">[1.3.3] - 2026-03-02 <a class="header-anchor" href="#_1-3-3-2026-03-02" aria-label="Permalink to &quot;[1.3.3] - 2026-03-02&quot;">​</a></h3><h4 id="セキュリティ" tabindex="-1">セキュリティ <a class="header-anchor" href="#セキュリティ" aria-label="Permalink to &quot;セキュリティ&quot;">​</a></h4><ul><li><strong>docs/site の依存関係脆弱性対応</strong>: <ul><li>rollup の脆弱性（GHSA-mw96-cpmx-2vgc）に対応するため、<code>docs/site</code> 側で rollup を安全なバージョン（<code>&gt;=4.59.0</code>）へ更新/固定。</li><li>関連PR: <a href="https://github.com/disnana/NanaSQLite/pull/99" target="_blank" rel="noreferrer">#99</a>, <a href="https://github.com/disnana/NanaSQLite/pull/102" target="_blank" rel="noreferrer">#102</a></li></ul></li></ul><h4 id="ci-開発環境-1" tabindex="-1">CI / 開発環境 <a class="header-anchor" href="#ci-開発環境-1" aria-label="Permalink to &quot;CI / 開発環境&quot;">​</a></h4><ul><li><strong>GitHub Actions の更新</strong>: <ul><li><code>actions/download-artifact</code> を v8 に更新。(<a href="https://github.com/disnana/NanaSQLite/pull/100" target="_blank" rel="noreferrer">#100</a>)</li><li><code>actions/upload-artifact</code> を v7 に更新。(<a href="https://github.com/disnana/NanaSQLite/pull/101" target="_blank" rel="noreferrer">#101</a>)</li><li><code>google/osv-scanner-action</code>（reusable / reusable-pr）を 2.3.3 に更新。(<a href="https://github.com/disnana/NanaSQLite/pull/97" target="_blank" rel="noreferrer">#97</a>, <a href="https://github.com/disnana/NanaSQLite/pull/98" target="_blank" rel="noreferrer">#98</a>)</li></ul></li></ul><h4 id="依存関係更新-メンテナンス" tabindex="-1">依存関係更新（メンテナンス） <a class="header-anchor" href="#依存関係更新-メンテナンス" aria-label="Permalink to &quot;依存関係更新（メンテナンス）&quot;">​</a></h4><ul><li><strong>リリース自動化アクション更新</strong>: <ul><li><code>softprops/action-gh-release</code> を v2 に更新。(<a href="https://github.com/disnana/NanaSQLite/pull/96" target="_blank" rel="noreferrer">#96</a>)</li></ul></li></ul><h4 id="備考" tabindex="-1">備考 <a class="header-anchor" href="#備考" aria-label="Permalink to &quot;備考&quot;">​</a></h4><ul><li>このリリースは主にメンテナンス（セキュリティ/CI/依存更新）を目的としたもので、ライブラリの公開API互換性に影響する変更は含みません。</li></ul><h3 id="_1-3-2-2026-01-17" tabindex="-1">[1.3.2] - 2026-01-17 <a class="header-anchor" href="#_1-3-2-2026-01-17" aria-label="Permalink to &quot;[1.3.2] - 2026-01-17&quot;">​</a></h3><h4 id="パフォーマンス最適化" tabindex="-1">パフォーマンス最適化 <a class="header-anchor" href="#パフォーマンス最適化" aria-label="Permalink to &quot;パフォーマンス最適化&quot;">​</a></h4><ul><li><strong>orjson 統合の最適化</strong>: <ul><li><code>_serialize()</code> メソッドの不要な変数割り当てを削除し、コード可読性と保守性を向上。</li><li>orjson による JSON エンコード/デコードが全暗号化パス（Fernet, AES-GCM, ChaCha20）で効果的に活用されることを確認・検証。</li><li>標準 <code>json</code> モジュールと比較して <strong>3~5倍の高速化</strong> を期待。</li><li>非同期処理（<code>AsyncNanaSQLite</code>）では ThreadPoolExecutor 経由で自動的に orjson の恩恵を受けるアーキテクチャを確認。</li></ul></li></ul><h4 id="コード品質改善-6" tabindex="-1">コード品質改善 <a class="header-anchor" href="#コード品質改善-6" aria-label="Permalink to &quot;コード品質改善&quot;">​</a></h4><ul><li><strong>本体コードの最適化</strong>: <ul><li>コード可読性を向上させ、変数スコープを明確化。</li></ul></li></ul><h4 id="テスト・検証" tabindex="-1">テスト・検証 <a class="header-anchor" href="#テスト・検証" aria-label="Permalink to &quot;テスト・検証&quot;">​</a></h4><ul><li><strong>orjson テストの実行確認</strong>: <ul><li><code>tests/test_json_backends.py</code> の全テストが正常に動作することを確認。</li><li>orjson 有無時の互換性テストが両環境で正常に実行。</li><li>JSON バックエンドの自動切り替え機能（HAS_ORJSON フラグ）が正常に動作。</li></ul></li></ul><h3 id="_1-3-1-2025-12-28" tabindex="-1">[1.3.1] - 2025-12-28 <a class="header-anchor" href="#_1-3-1-2025-12-28" aria-label="Permalink to &quot;[1.3.1] - 2025-12-28&quot;">​</a></h3><h4 id="新機能-オプションのデータ暗号化" tabindex="-1">新機能: オプションのデータ暗号化 <a class="header-anchor" href="#新機能-オプションのデータ暗号化" aria-label="Permalink to &quot;新機能: オプションのデータ暗号化&quot;">​</a></h4><ul><li><strong>マルチモード暗号化</strong>: <code>cryptography</code> を使用した透過的な暗号化を実装。 <ul><li><strong>AES-GCM (デフォルト)</strong>: 安全かつ高速。ハードウェア加速(AES-NI)対応環境で最適。</li><li><strong>ChaCha20-Poly1305</strong>: ハードウェア加速がない環境（ARM等）でも高速なソフトウェア実装。</li><li><strong>Fernet</strong>: 従来通りの使いやすさと互換性重視のオプション。</li><li><code>NanaSQLite</code> および <code>AsyncNanaSQLite</code> に <code>encryption_key</code> および <code>encryption_mode</code> 引数を追加。</li><li>SQLite への保存前に暗号化し、取得時に自動復号。</li><li><strong>ハイブリッド設計</strong>: メモリキャッシュ内は平文で保持されるため、暗号化有効時も高速なリードパフォーマンスを維持。</li></ul></li><li><strong>拡張インストール</strong>: <code>pip install nanasqlite[encryption]</code> で必要な依存関係を含めてインストール可能に。</li></ul><h4 id="新機能-柔軟なキャッシュ戦略と-ttl-サポート-v1-3-1-alpha-0" tabindex="-1">新機能: 柔軟なキャッシュ戦略と TTL サポート (v1.3.1-alpha.0) <a class="header-anchor" href="#新機能-柔軟なキャッシュ戦略と-ttl-サポート-v1-3-1-alpha-0" aria-label="Permalink to &quot;新機能: 柔軟なキャッシュ戦略と TTL サポート (v1.3.1-alpha.0)&quot;">​</a></h4><ul><li><strong>TTL (Time-To-Live) キャッシュ</strong>: <code>cache_strategy=CacheType.TTL, cache_ttl=seconds</code> でデータの有効期限を設定可能に。</li><li><strong>Persistence TTL (自動削除)</strong>: <code>cache_persistence_ttl=True</code> で失効時に SQLite からも自動削除。</li><li><strong>FIFO 制限付き Unbounded</strong>: 無制限キャッシュでも <code>cache_size</code> 指定で FIFO 方式のメモリ制限が可能。</li><li><strong>キャッシュクリア API</strong>: <code>db.clear_cache()</code> および非同期版 <code>aclear_cache()</code> を追加。</li></ul><h4 id="改良と修正" tabindex="-1">改良と修正 <a class="header-anchor" href="#改良と修正" aria-label="Permalink to &quot;改良と修正&quot;">​</a></h4><ul><li><strong>最適化された <code>ExpiringDict</code></strong>: 低オーバーヘッドかつ高精度な有効期限管理ユーティリティを内部実装。</li><li><strong>後方互換性の維持</strong>: デフォルトの <code>UNBOUNDED</code> モードでは従来通りの高速パスを維持しつつ、制限設定時のみインターセプトを適用。</li><li><strong>型安全性の向上</strong>: <code>mypy</code> と <code>ruff</code> による厳格なチェックを通過し、型ヒントを強化。</li><li><strong>ベンチマークの統合</strong>: <code>tests/test_benchmark.py</code> (Sync) と <code>tests/test_async_benchmark.py</code> (Async) に暗号化・キャッシュ戦略のベンチマークを集約し、可視性を向上。</li><li><strong>テストカバレッジ</strong>: 非同期環境におけるキャッシュ挙動（LRU退避、TTL失効）の検証テスト <code>tests/test_async_cache.py</code> を追加。</li></ul><h3 id="_1-3-0dev0-2025-12-27" tabindex="-1">[1.3.0dev0] - 2025-12-27 <a class="header-anchor" href="#_1-3-0dev0-2025-12-27" aria-label="Permalink to &quot;[1.3.0dev0] - 2025-12-27&quot;">​</a></h3><h4 id="新機能-柔軟なキャッシュ戦略" tabindex="-1">新機能: 柔軟なキャッシュ戦略 <a class="header-anchor" href="#新機能-柔軟なキャッシュ戦略" aria-label="Permalink to &quot;新機能: 柔軟なキャッシュ戦略&quot;">​</a></h4><ul><li><strong><code>CacheType</code> 列挙型の追加</strong>: <code>UNBOUNDED</code> (無制限、従来動作) と <code>LRU</code> (追い出し型) を選択可能に。</li><li><strong>LRUキャッシュの実装</strong>: <code>cache_strategy=CacheType.LRU, cache_size=N</code> でメモリ使用量を制限可能。</li><li><strong>テーブル別設定</strong>: <code>db.table(&quot;logs&quot;, cache_strategy=CacheType.LRU, cache_size=100)</code> で個別設定。</li><li><strong>高速化オプション</strong>: <code>pip install nanasqlite[speed]</code> で C拡張 <code>lru-dict</code> を導入し、最大2倍の速度向上。</li><li><strong>自動フォールバック</strong>: <code>lru-dict</code> 未インストール時は標準ライブラリ <code>OrderedDict</code> を使用。</li></ul><h4 id="新規テスト" tabindex="-1">新規テスト <a class="header-anchor" href="#新規テスト" aria-label="Permalink to &quot;新規テスト&quot;">​</a></h4><ul><li><code>tests/test_cache.py</code>: キャッシュ戦略の包括的テストスイート（追い出し、永続化、テーブル別設定）。</li></ul><h3 id="_1-2-2b1-2025-12-27" tabindex="-1">[1.2.2b1] - 2025-12-27 <a class="header-anchor" href="#_1-2-2b1-2025-12-27" aria-label="Permalink to &quot;[1.2.2b1] - 2025-12-27&quot;">​</a></h3><h4 id="ドキュメントとブランドの刷新" tabindex="-1">ドキュメントとブランドの刷新 <a class="header-anchor" href="#ドキュメントとブランドの刷新" aria-label="Permalink to &quot;ドキュメントとブランドの刷新&quot;">​</a></h4><ul><li><strong>超モダンなドキュメントサイトの構築</strong>: <ul><li>VitePress + Tailwind CSS を採用し、デザイン性とブラウジング体験を大幅に向上させた公式サイトを <code>docs/site</code> に構築。</li><li><strong>公式SVGロゴの制作</strong>: 辞書 <code>{ }</code> とデータスタックを融合させた独自シンボルを開発。100%透過、ダークモード自動対応（反転フィルタ）、無限解像度のベクター形式。</li><li><strong>多言語APIリファレンスの真の分離</strong>: docstringからターゲット言語（日・英）のみを抽出・整形するインテリジェントな生成エンジンを実装。</li></ul></li><li><strong>自動化と公開</strong>: <ul><li>GitHub Actions による docs 自動ビルド・公開ワークフロー (<code>deploy-docs.yml</code>) を導入。</li><li>公開時に <code>gh-pages</code> ブランチの過去のベンチマーク履歴を自動取得・マージし、履歴を保護するロジックを実装。</li></ul></li></ul><h4 id="セキュリティと安定性の向上" tabindex="-1">セキュリティと安定性の向上 <a class="header-anchor" href="#セキュリティと安定性の向上" aria-label="Permalink to &quot;セキュリティと安定性の向上&quot;">​</a></h4><ul><li><strong>SQL検証の適正化</strong>: <ul><li><code>||</code> (文字列連結) 演算子を高速検証の許可リストに追加し、複雑なエイリアスを含むクエリでの誤検知を解消。</li></ul></li><li><strong>CI/CDの安定化</strong>: <ul><li><code>ruff</code> の最新ルールに基づき、<code>core.py</code> および <code>gen_api_docs.py</code> のインポート順序を厳密に整理。</li><li>依存関係の欠落を防ぐため、docsビルド時の依存管理を強化。</li></ul></li></ul><h3 id="_1-2-2a1-2025-12-26" tabindex="-1">[1.2.2a1] - 2025-12-26 <a class="header-anchor" href="#_1-2-2a1-2025-12-26" aria-label="Permalink to &quot;[1.2.2a1] - 2025-12-26&quot;">​</a></h3><h4 id="開発ツール-ベンチマーク・ci-cd" tabindex="-1">開発ツール (ベンチマーク・CI/CD) <a class="header-anchor" href="#開発ツール-ベンチマーク・ci-cd" aria-label="Permalink to &quot;開発ツール (ベンチマーク・CI/CD)&quot;">​</a></h4><ul><li><strong>ベンチマークの性能比較ロジックを修正</strong>: <ul><li>比較計算を Ops/sec ベースに統一し、速度向上時に正しく <code>+</code>（🚀/✅）が表示されるように改善。</li><li>サマリーテーブルに Ops/sec の絶対値の差分（例: <code>+2.1M ops</code>）を追加。</li><li><strong>Ops/sec 計算の正確性向上</strong>: 平均時間からの逆算（近似値）ではなく、ベンチマークツールの生データ (<code>ops</code>) を直接使用するように修正。これにより、OS別詳細表示で <code>(0.0)</code> と表示されるバグも解消。</li><li>0.001ms 未満の微小な時間計測結果に対して <code>ns</code> (nanoseconds) 単位を正しく表示。</li><li>絵文字（🚀, ✅, ➖, ⚠️, 🔴）による直感的なパフォーマンス評価を追加。</li></ul></li><li><strong>CI/CDワークフローの最適化</strong>: <ul><li><code>benchmark.yml</code>: GitHub Actions ランナーの性能ばらつき（10-60%）を考慮し、ベンチマークを「情報提供のみ」に変更。性能低下による CI 失敗を防止。</li><li><code>ci.yml</code>: トリガーを最適化し、<code>push</code> による自動実行を <code>main</code> ブランチのみに限定。他ブランチは <code>workflow_dispatch</code> で手動実行可能に。</li><li><code>should-run</code> ジョブの判定ロジックを簡略化。</li></ul></li></ul><h3 id="_1-2-1b2-2025-12-25" tabindex="-1">[1.2.1b2] - 2025-12-25 <a class="header-anchor" href="#_1-2-1b2-2025-12-25" aria-label="Permalink to &quot;[1.2.1b2] - 2025-12-25&quot;">​</a></h3><h4 id="開発ツール" tabindex="-1">開発ツール <a class="header-anchor" href="#開発ツール" aria-label="Permalink to &quot;開発ツール&quot;">​</a></h4><ul><li><strong>CI/CDワークフローの統合</strong>: <ul><li><code>lint.yml</code>, <code>test.yml</code>, <code>publish.yml</code>, <code>quality-gate.yml</code> を一つの <code>ci.yml</code> に統合。</li><li>リリースサマリーにPyPIとGitHub Releaseへの直接リンク、詳細なジョブステータス（Cancelled/Skipped対応）を追加。</li></ul></li><li><strong>テスト環境の最適化</strong>: <ul><li>CIテストマトリックスを調整。Ubuntuは全バージョン、Windows/macOSは利用率の高い Python 3.11および3.13に絞り込み、実行時間を短縮。</li><li>dev依存関係に <code>pytest-xdist</code> を追加し、並列テストをサポート。</li></ul></li><li><strong>型チェックの改善</strong>: <ul><li>mypy設定の緩和と整理により、156件の型エラーを解消（<code>--no-strict-optional</code> の導入とエラーコードの個別制御）。</li></ul></li></ul><h4 id="開発ツール-1" tabindex="-1">開発ツール <a class="header-anchor" href="#開発ツール-1" aria-label="Permalink to &quot;開発ツール&quot;">​</a></h4><ul><li><strong>リント・CI環境の追加</strong>: <ul><li><code>tox.ini</code> を追加し、<code>tox -e lint</code> (ruff), <code>tox -e type</code> (mypy), <code>tox -e format</code>, <code>tox -e fix</code> の環境を構築。</li><li><code>pyproject.toml</code> にruff設定を追加（E/W/F/I/B/UP/N/ASYNCルール、Python 3.9+対応、line-length: 120）。</li><li><code>pyproject.toml</code> にmypy設定を追加（<code>--no-strict-optional</code>フラグ使用、実用的な型チェック）。</li><li><code>.github/workflows/lint.yml</code> を追加：PyPA/twineスタイルのCIワークフロー（tox統合、FORCE_COLOR対応、サマリー出力）。</li><li><code>.github/workflows/quality-gate.yml</code> を追加：all-greenゲートでmainブランチ判定とpublish準備確認。</li><li>dev依存関係に <code>tox&gt;=4.0.0</code>, <code>ruff&gt;=0.8.0</code>, <code>mypy&gt;=1.13.0</code> を追加。</li></ul></li><li><strong>コード品質改善</strong>: <ul><li>ruff auto-fixで1373件のリントエラーを修正（import順序、未使用import削除、pyupgrade、whitespace等）。</li><li>B904 (raise without from), B017 (assert raises Exception) をignore listに追加。</li><li>mypy設定を実用的に調整（156エラー → 0エラー）。</li></ul></li></ul><h3 id="_1-2-0b1-2025-12-24" tabindex="-1">[1.2.0b1] - 2025-12-24 <a class="header-anchor" href="#_1-2-0b1-2025-12-24" aria-label="Permalink to &quot;[1.2.0b1] - 2025-12-24&quot;">​</a></h3><h4 id="セキュリティと堅牢性" tabindex="-1">セキュリティと堅牢性 <a class="header-anchor" href="#セキュリティと堅牢性" aria-label="Permalink to &quot;セキュリティと堅牢性&quot;">​</a></h4><ul><li><strong><code>ORDER BY</code> 解析の強化</strong>: <ul><li><code>NanaSQLite</code> に専用のパーサー <code>_parse_order_by_clause</code> を実装し、複雑な <code>ORDER BY</code> 句を安全に処理・検証できるようにしました。</li><li>正当なソートパターンをサポートしつつ、SQLインジェクションに対する保護を強化しました。</li></ul></li><li><strong>厳格な検証の修正</strong>: <ul><li>危険なパターン（<code>;</code>, <code>--</code>, <code>/*</code>）に対するエラーメッセージを <code>Invalid [label]: [message]</code> の形式に統一しました。</li><li>すべての検証エラーに対して統一されたメッセージ形式を適用することで、レガシーテストと新しいセキュリティテスト間の一貫した動作を保証しました。</li></ul></li></ul><h4 id="リファクタリング" tabindex="-1">リファクタリング <a class="header-anchor" href="#リファクタリング" aria-label="Permalink to &quot;リファクタリング&quot;">​</a></h4><ul><li><strong>コード構成</strong>: <ul><li><code>_sanitize_sql_for_function_scan</code> ロジックを新しい <code>nanasqlite.sql_utils</code> モジュールに抽出・移動し、保守性を向上させました。</li><li><code>AsyncNanaSQLite</code> の <code>query</code> と <code>query_with_pagination</code> メソッドから重複コードを削除し、共通ロジックを <code>_shared_query_impl</code> ヘルパーメソッドに統合しました（約150行の削減）。</li></ul></li><li><strong>型安全性</strong>: <ul><li><code>context</code> パラメータに <code>Literal</code> 型ヒントを追加し、IDEサポートと型チェックを強化しました (PR #36)。</li></ul></li></ul><h4 id="修正と改善" tabindex="-1">修正と改善 <a class="header-anchor" href="#修正と改善" aria-label="Permalink to &quot;修正と改善&quot;">​</a></h4><ul><li><strong>非同期ロギング</strong>: <ul><li>読み取り専用プールのクリーンアップ中に発生するエラーのログレベルを DEBUG から WARNING に引き上げ、リソースの問題を検知しやすくしました。</li><li>エラーメッセージに接続コンテキスト情報を追加しました。</li></ul></li><li><strong>非同期プールクリーンアップの堅牢性向上</strong>: <ul><li><code>AsyncNanaSQLite.close()</code> メソッドにおいて、プール内の一部の接続でエラーが発生しても、残りの接続を確実にクリーンアップするように改善しました。</li><li><code>AttributeError</code> 発生時に <code>break</code> していた処理を継続するように変更し、リソースリークを防止します。</li></ul></li><li><strong>テスト</strong>: <ul><li>インスタンスがクローズされている場合に <code>__eq__</code> が正しく <code>NanaSQLiteClosedError</code> を送出するように修正しました (PR #44)。</li><li>セキュリティテストにおける例外ハンドリングの具体性を向上させました (PR #43)。</li><li>セキュリティテストのコメントを明確化し、検証タイミングの説明を追加しました (PR #35)。</li><li>重複していた <code>pytest</code> インポートを削除し、一時的なテストファイル（<code>temp_test_parser.py</code>）を整理しました。</li></ul></li></ul><h3 id="_1-2-0a2-2025-12-23" tabindex="-1">[1.2.0a2] - 2025-12-23 <a class="header-anchor" href="#_1-2-0a2-2025-12-23" aria-label="Permalink to &quot;[1.2.0a2] - 2025-12-23&quot;">​</a></h3><ul><li><strong>非同期セキュリティ機能の強化</strong>: <ul><li><code>AsyncNanaSQLite.query</code> および <code>query_with_pagination</code> において、<code>allowed_sql_functions</code>, <code>forbidden_sql_functions</code>, <code>override_allowed</code> が正しく <code>_validate_expression</code> に渡されるように修正。</li><li><code>AsyncNanaSQLite</code> の非同期セキュリティテスト (<code>tests/test_security_async_v120.py</code>) を追加。</li></ul></li><li><strong>非同期接続管理の改善</strong>: <ul><li><code>AsyncNanaSQLite</code> にクローズ状態を追跡する <code>_closed</code> フラグを追加。</li><li>親インスタンスがクローズされた際に、<code>table()</code> で作成された子インスタンスも即座にクローズ状態となるように改善。</li><li>未初期化のインスタンスをクローズした場合でも、その後の操作で正しく <code>NanaSQLiteClosedError</code> が発生するように修正。</li></ul></li></ul><h3 id="_1-2-0a1-2025-12-23" tabindex="-1">[1.2.0a1] - 2025-12-23 <a class="header-anchor" href="#_1-2-0a1-2025-12-23" aria-label="Permalink to &quot;[1.2.0a1] - 2025-12-23&quot;">​</a></h3><ul><li><strong>非同期読み取り専用接続プール</strong>: <ul><li><code>AsyncNanaSQLite</code> に <code>read_pool_size</code> 引数を追加。</li><li><code>query</code>, <code>query_with_pagination</code>, <code>fetch_all</code>, <code>fetch_one</code> メソッドで読み取り専用プールを使用可能に。</li><li>安全性のため、プール接続は常に <code>read-only</code> モードで動作。</li></ul></li><li><strong>バグ修正</strong>: <ul><li><code>query</code> および <code>query_with_pagination</code> で結果が0件の場合に発生していた <code>apsw.ExecutionCompleteError</code> を修正。</li><li>カラム名の取得方法を <code>cursor.description</code> 依存から同期版と同様の <code>PRAGMA table_info</code> および手動パース方式に変更。</li></ul></li></ul><h3 id="_1-2-0dev1-2025-12-23" tabindex="-1">[1.2.0dev1] - 2025-12-23 <a class="header-anchor" href="#_1-2-0dev1-2025-12-23" aria-label="Permalink to &quot;[1.2.0dev1] - 2025-12-23&quot;">​</a></h3><h4 id="修正-2" tabindex="-1">修正 <a class="header-anchor" href="#修正-2" aria-label="Permalink to &quot;修正&quot;">​</a></h4><ul><li><strong>非同期APIの一貫性向上</strong>: <ul><li><code>AsyncNanaSQLite</code> に全てのメソッドの <code>a</code> プレフィックス付きエイリアス（<code>abatch_update</code>, <code>ato_dict</code> 等）を追加。</li><li>ベンチマークテスト (<code>test_async_benchmark.py</code>) でのメソッド未定義エラーを解消。</li></ul></li><li><strong>後方互換性の修正</strong>: <ul><li>SQLインジェクション検知時のエラーメッセージを <code>test_security.py</code> 等の既存テストが期待する形式（&quot;Invalid order_by clause&quot; 等）に再調整。</li><li><code>test_enhancements.py</code> において <code>NanaSQLiteClosedError</code> を許容するように修正し、例外クラス名チェックとの整合性を確保。</li></ul></li><li><strong>Windows環境の安定性向上</strong>: <ul><li><code>test_security_v120.py</code> で <code>pytest</code> の <code>tmp_path</code> フィクスチャを使用するように変更し、Windowsでの <code>BusyError</code> や <code>IOError</code> を回避。</li></ul></li><li><strong><code>query</code>/<code>query_with_pagination</code> のバグ修正</strong>: <ul><li><code>limit=0</code> および <code>offset=0</code> が無視されていた問題を修正。<code>if limit:</code> から <code>if limit is not None:</code> に変更。</li><li>⚠️ <strong>後方互換性</strong>: 以前は <code>limit=0</code> を渡すと全件取得していましたが、今後は正しく0件を返します。<code>limit=0</code> を「制限なし」の意味で使用していた場合は <code>limit=None</code> に変更してください。</li></ul></li><li><strong>エッジケーステストの追加</strong>: <ul><li><code>tests/test_edge_cases_v120.py</code> を新規作成。空リストでの <code>batch_*</code> 操作やページネーションの境界値テストを追加。</li></ul></li></ul><h3 id="_1-2-0dev0-2025-12-22" tabindex="-1">[1.2.0dev0] - 2025-12-22 <a class="header-anchor" href="#_1-2-0dev0-2025-12-22" aria-label="Permalink to &quot;[1.2.0dev0] - 2025-12-22&quot;">​</a></h3><h4 id="追加" tabindex="-1">追加 <a class="header-anchor" href="#追加" aria-label="Permalink to &quot;追加&quot;">​</a></h4><ul><li><strong>セキュリティ強化 (Phase 1)</strong>: <ul><li><code>strict_sql_validation</code> フラグの導入（未許可関数の使用時に例外または警告）。</li><li><code>max_clause_length</code> による動的SQLの長さ制限（ReDoS対策）。</li><li>文字列ベースの危険なSQLパターン（<code>;</code>, <code>--</code>, <code>/*</code>）およびSQLキーワード（<code>DROP</code>, <code>DELETE</code> 等）の検知ロジックの強化。</li></ul></li><li><strong>接続管理の厳格化</strong>: <ul><li><code>NanaSQLiteClosedError</code> の導入。</li><li>親インスタンス・クローズ時に子インスタンス（<code>table()</code>で作成）を自動的に無効化する追跡機構の実装。</li></ul></li><li><strong>メンテナンス性向上</strong>: <ul><li><code>DEVELOPMENT_GUIDE.md</code> の作成（日英）。</li><li><code>pip install -e . -U</code> による環境同期ルールの明文化。</li></ul></li></ul><h3 id="_1-1-0-2025-12-19" tabindex="-1">[1.1.0] - 2025-12-19 <a class="header-anchor" href="#_1-1-0-2025-12-19" aria-label="Permalink to &quot;[1.1.0] - 2025-12-19&quot;">​</a></h3><h4 id="追加-1" tabindex="-1">追加 <a class="header-anchor" href="#追加-1" aria-label="Permalink to &quot;追加&quot;">​</a></h4><ul><li><p><strong>カスタム例外クラスの導入</strong>:</p><ul><li><code>NanaSQLiteError</code> (基底クラス)</li><li><code>NanaSQLiteValidationError</code> (バリデーションエラー)</li><li><code>NanaSQLiteDatabaseError</code> (データベース操作エラー)</li><li><code>NanaSQLiteTransactionError</code> (トランザクション関連エラー)</li><li><code>NanaSQLiteConnectionError</code> (接続エラー)</li><li><code>NanaSQLiteLockError</code> (ロックエラー、将来用)</li><li><code>NanaSQLiteCacheError</code> (キャッシュエラー、将来用)</li></ul></li><li><p><strong>バッチ取得機能 (<code>batch_get</code>)</strong>:</p><ul><li><code>batch_get(keys: List[str])</code> による効率的な複数キーの一括ロード</li><li><code>AsyncNanaSQLite.abatch_get(keys)</code> による非同期サポート</li><li>1回のクエリで複数データを取得しキャッシュを最適化</li></ul></li><li><p><strong>トランザクション管理の強化</strong>:</p><ul><li>トランザクション状態の追跡（<code>_in_transaction</code>, <code>_transaction_depth</code>）</li><li>ネストしたトランザクションの検出とエラー発生</li><li><code>in_transaction()</code> メソッドの追加</li><li>トランザクション中の接続クローズを防止</li><li>トランザクション外でのcommit/rollbackを検出</li></ul></li><li><p><strong>非同期版トランザクション対応</strong>:</p><ul><li><code>AsyncNanaSQLite.begin_transaction()</code></li><li><code>AsyncNanaSQLite.commit()</code></li><li><code>AsyncNanaSQLite.rollback()</code></li><li><code>AsyncNanaSQLite.in_transaction()</code></li><li><code>AsyncNanaSQLite.transaction()</code> (コンテキストマネージャ)</li><li><code>_AsyncTransactionContext</code> クラスの実装</li></ul></li><li><p><strong>リソースリーク対策</strong>:</p><ul><li>親インスタンスが子インスタンスを弱参照で追跡</li><li>親が閉じられた際、子インスタンスに通知</li><li>孤立した子インスタンスの使用を防止</li><li><code>_check_connection()</code> メソッドの追加</li><li><code>_mark_parent_closed()</code> メソッドの追加</li></ul></li></ul><h4 id="改善" tabindex="-1">改善 <a class="header-anchor" href="#改善" aria-label="Permalink to &quot;改善&quot;">​</a></h4><ul><li><p><strong>エラーハンドリングの強化</strong>:</p><ul><li><code>execute()</code> メソッドにエラーハンドリングを追加</li><li>APSWの例外を <code>NanaSQLiteDatabaseError</code> でラップ</li><li>元のエラー情報を保持（<code>original_error</code> 属性）</li><li>接続状態のチェックを各メソッドに追加</li><li><code>_sanitize_identifier()</code> で <code>NanaSQLiteValidationError</code> を使用</li></ul></li><li><p><strong><code>__setitem__</code> メソッドに接続チェックを追加</strong></p></li></ul><h4 id="ドキュメント-2" tabindex="-1">ドキュメント <a class="header-anchor" href="#ドキュメント-2" aria-label="Permalink to &quot;ドキュメント&quot;">​</a></h4><ul><li><p><strong>新規ドキュメント</strong>:</p><ul><li><code>docs/ja/error_handling.md</code> - エラーハンドリングガイド</li><li><code>docs/ja/transaction_guide.md</code> - トランザクションガイド</li><li><code>docs/ja/implementation_status.md</code> - 実装状況と今後の計画</li><li><code>tests/test_enhancements.py</code> - 強化機能のテスト（21件）</li></ul></li><li><p><strong>README更新</strong>:</p><ul><li>トランザクションサポートのセクションを追加</li><li>カスタム例外のサンプルコードを追加</li><li>非同期版のトランザクションサンプルを追加</li></ul></li></ul><h4 id="テスト-3" tabindex="-1">テスト <a class="header-anchor" href="#テスト-3" aria-label="Permalink to &quot;テスト&quot;">​</a></h4><ul><li><strong>新規テスト</strong>（21件）: <ul><li>カスタム例外クラスのテスト（5件）</li><li>トランザクション機能の強化テスト（6件）</li><li>リソース管理のテスト（3件）</li><li>エラーハンドリングのテスト（2件）</li><li>トランザクションと例外の組み合わせテスト（2件）</li><li>非同期版トランザクションのテスト（3件）</li></ul></li></ul><h4 id="修正-3" tabindex="-1">修正 <a class="header-anchor" href="#修正-3" aria-label="Permalink to &quot;修正&quot;">​</a></h4><ul><li>セキュリティテストで <code>NanaSQLiteValidationError</code> を期待するように修正</li></ul><hr><h3 id="_1-1-0a3-2025-12-17" tabindex="-1">[1.1.0a3] - 2025-12-17 <a class="header-anchor" href="#_1-1-0a3-2025-12-17" aria-label="Permalink to &quot;[1.1.0a3] - 2025-12-17&quot;">​</a></h3><h4 id="ドキュメント改善" tabindex="-1">ドキュメント改善 <a class="header-anchor" href="#ドキュメント改善" aria-label="Permalink to &quot;ドキュメント改善&quot;">​</a></h4><ul><li><strong><code>table()</code>メソッドの使用上の注意を追加</strong>: <ul><li>README.mdに重要な使用上の注意セクションを追加（英語・日本語）</li><li>同じテーブルへの複数インスタンス作成に関する警告</li><li>コンテキストマネージャ使用の推奨</li><li>ベストプラクティスの明記</li></ul></li><li><strong>docstring改善</strong>: <ul><li><code>NanaSQLite.table()</code>のdocstringに詳細な注意事項を追加</li><li><code>AsyncNanaSQLite.table()</code>のdocstringに詳細な注意事項を追加</li><li>非推奨パターンと推奨パターンの具体例を追加</li></ul></li><li><strong>将来的な改善計画</strong>: <ul><li><code>etc/future_plans/</code>ディレクトリに改善提案を文書化</li><li>重複インスタンス検出警告機能（提案B）</li><li>接続状態チェック機能（提案B）</li><li>共有キャッシュ機構（提案C - 保留）</li></ul></li></ul><h4 id="分析・調査" tabindex="-1">分析・調査 <a class="header-anchor" href="#分析・調査" aria-label="Permalink to &quot;分析・調査&quot;">​</a></h4><ul><li><strong>table()機能の包括的な調査を実施</strong>: <ul><li>ストレステスト: 7件すべて合格</li><li>エッジケーステスト: 10件実施</li><li>並行処理テスト: 5件すべて合格</li><li><strong>発見された問題</strong>: 2件（軽微な設計上の制限） <ol><li>同一テーブルへの複数インスタンスでキャッシュ不整合（ドキュメント化で対応）</li><li>close後のサブインスタンスアクセス（ドキュメント化で対応）</li></ol></li><li><strong>結論</strong>: 本番環境で使用可能、パフォーマンス問題なし</li></ul></li></ul><h3 id="_1-1-0dev2-2025-12-16" tabindex="-1">[1.1.0dev2] - 2025-12-16 <a class="header-anchor" href="#_1-1-0dev2-2025-12-16" aria-label="Permalink to &quot;[1.1.0dev2] - 2025-12-16&quot;">​</a></h3><h4 id="現在の開発状況" tabindex="-1">現在の開発状況 <a class="header-anchor" href="#現在の開発状況" aria-label="Permalink to &quot;現在の開発状況&quot;">​</a></h4><ul><li>開発中のバージョン</li><li>テスト実施中（<code>test_concurrent_table_writes.py</code>で15個のテスト全てパス）</li></ul><h3 id="_1-1-0dev1-2025-12-15" tabindex="-1">[1.1.0dev1] - 2025-12-15 <a class="header-anchor" href="#_1-1-0dev1-2025-12-15" aria-label="Permalink to &quot;[1.1.0dev1] - 2025-12-15&quot;">​</a></h3><h4 id="追加-2" tabindex="-1">追加 <a class="header-anchor" href="#追加-2" aria-label="Permalink to &quot;追加&quot;">​</a></h4><ul><li><strong>マルチテーブルサポート（<code>table()</code>メソッド）</strong>: 同一データベース内の複数テーブルを安全に操作 <ul><li><code>db.table(table_name)</code>で別テーブル用のインスタンスを取得</li><li><strong>接続とロックの共有</strong>: 複数のテーブルインスタンスが同じSQLite接続とスレッドロックを共有</li><li>スレッドセーフ: 複数スレッドから異なるテーブルへの同時書き込みが安全に動作</li><li>メモリ効率: 接続を再利用することでリソースを節約</li><li><strong>同期版</strong>: <code>NanaSQLite.table(table_name)</code> → <code>NanaSQLite</code>インスタンス</li><li><strong>非同期版</strong>: <code>await AsyncNanaSQLite.table(table_name)</code> → <code>AsyncNanaSQLite</code>インスタンス</li><li>キャッシュ分離: 各テーブルインスタンスは独立したメモリキャッシュを保持</li></ul></li></ul><h4 id="内部実装の改善" tabindex="-1">内部実装の改善 <a class="header-anchor" href="#内部実装の改善" aria-label="Permalink to &quot;内部実装の改善&quot;">​</a></h4><ul><li><strong>スレッドセーフティの強化</strong>: 全データベース操作に<code>threading.RLock</code>を追加 <ul><li>読み込み（<code>_read_from_db</code>）、書き込み（<code>_write_to_db</code>）、削除（<code>_delete_from_db</code>）</li><li>クエリ実行（<code>execute</code>, <code>execute_many</code>）</li><li>トランザクション操作</li></ul></li><li><strong>接続管理の改善</strong>: <ul><li><code>_shared_connection</code>パラメータで接続の共有をサポート</li><li><code>_shared_lock</code>パラメータでロックの共有をサポート</li><li><code>_is_connection_owner</code>フラグで接続の所有権を管理</li><li><code>close()</code>メソッドは接続の所有者のみが実行</li></ul></li></ul><h4 id="テスト-4" tabindex="-1">テスト <a class="header-anchor" href="#テスト-4" aria-label="Permalink to &quot;テスト&quot;">​</a></h4><ul><li><strong>15の包括的なテストケース</strong>（全てパス）: <ul><li>同期版マルチテーブル並行書き込みテスト（2テーブル、複数テーブル）</li><li>非同期版マルチテーブル並行書き込みテスト（2テーブル、複数テーブル）</li><li>ストレステスト（1000件の並行書き込み）</li><li>キャッシュ分離テスト</li><li>テーブル切り替えテスト</li><li>エッジケーステスト</li></ul></li></ul><h4 id="互換性" tabindex="-1">互換性 <a class="header-anchor" href="#互換性" aria-label="Permalink to &quot;互換性&quot;">​</a></h4><ul><li><strong>完全な後方互換性</strong>: 既存のコードに影響なし</li><li>新しいパラメータはすべてオプショナル（内部使用）</li></ul><h3 id="_1-0-3rc7-2025-12-10" tabindex="-1">[1.0.3rc7] - 2025-12-10 <a class="header-anchor" href="#_1-0-3rc7-2025-12-10" aria-label="Permalink to &quot;[1.0.3rc7] - 2025-12-10&quot;">​</a></h3><h4 id="追加-3" tabindex="-1">追加 <a class="header-anchor" href="#追加-3" aria-label="Permalink to &quot;追加&quot;">​</a></h4><ul><li><strong>非同期サポート（AsyncNanaSQLite）</strong>: 非同期アプリケーション向けの完全な非同期インターフェース <ul><li><code>AsyncNanaSQLite</code>クラス: 全操作の非同期版を提供</li><li><strong>専用スレッドプールエグゼキューター</strong>: 設定可能なmax_workers（デフォルト5）で最適化</li><li><code>ThreadPoolExecutor</code>による高性能な並行処理</li><li>FastAPI、aiohttp等の非同期フレームワークで安全に使用可能</li><li>非同期dict風インターフェース: <code>await db.aget()</code>, <code>await db.aset()</code>, <code>await db.adelete()</code></li><li>非同期バッチ操作: <code>await db.batch_update()</code>, <code>await db.batch_delete()</code></li><li>非同期SQL実行: <code>await db.execute()</code>, <code>await db.query()</code></li><li>非同期コンテキストマネージャ: <code>async with AsyncNanaSQLite(...) as db:</code></li><li>並行処理サポート: 複数の非同期操作を並行実行可能</li><li>自動リソース管理: スレッドプールの自動クリーンアップ</li></ul></li><li><strong>包括的なテストスイート</strong>: 100以上の非同期テストケース <ul><li>基本操作、並行処理、エラーハンドリング、パフォーマンステスト</li><li>全テストが合格</li></ul></li><li><strong>完全な後方互換性</strong>: 既存の<code>NanaSQLite</code>クラスは変更なし</li></ul><h4 id="パフォーマンス改善-6" tabindex="-1">パフォーマンス改善 <a class="header-anchor" href="#パフォーマンス改善-6" aria-label="Permalink to &quot;パフォーマンス改善&quot;">​</a></h4><ul><li>非同期アプリでのブロッキング防止により、イベントループの応答性が向上</li><li>専用スレッドプールによる高効率な並行処理（設定可能なワーカー数）</li><li>APSW + スレッドプールの組み合わせで最適なパフォーマンス</li><li>高負荷環境向けにmax_workersを調整可能（5～50）</li></ul><h3 id="_1-0-3rc6-2025-12-10" tabindex="-1">[1.0.3rc6] - 2025-12-10 <a class="header-anchor" href="#_1-0-3rc6-2025-12-10" aria-label="Permalink to &quot;[1.0.3rc6] - 2025-12-10&quot;">​</a></h3><h4 id="追加-4" tabindex="-1">追加 <a class="header-anchor" href="#追加-4" aria-label="Permalink to &quot;追加&quot;">​</a></h4><ul><li><strong><code>get_fresh(key, default=None)</code>メソッド</strong>: DBから直接読み込み、キャッシュを更新して値を返す <ul><li><code>execute()</code>でDBを直接変更した後のキャッシュ同期に便利</li><li><code>_read_from_db</code>を直接使用してオーバーヘッドを最小化</li></ul></li></ul><h3 id="_1-0-3rc5-2025-12-10" tabindex="-1">[1.0.3rc5] - 2025-12-10 <a class="header-anchor" href="#_1-0-3rc5-2025-12-10" aria-label="Permalink to &quot;[1.0.3rc5] - 2025-12-10&quot;">​</a></h3><h4 id="パフォーマンス改善-7" tabindex="-1">パフォーマンス改善 <a class="header-anchor" href="#パフォーマンス改善-7" aria-label="Permalink to &quot;パフォーマンス改善&quot;">​</a></h4><ul><li><strong><code>batch_update()</code>の最適化</strong>: <code>executemany</code>使用で大量データ処理が10-30%高速化</li><li><strong><code>batch_delete()</code>の最適化</strong>: <code>executemany</code>使用で一括削除が高速化</li><li><strong><code>__contains__()</code>の最適化</strong>: 軽量なEXISTSクエリ使用で存在確認が高速化（大きなvalueの場合に効果大）</li></ul><h4 id="ide-型サポート強化" tabindex="-1">IDE/型サポート強化 <a class="header-anchor" href="#ide-型サポート強化" aria-label="Permalink to &quot;IDE/型サポート強化&quot;">​</a></h4><ul><li><code>from __future__ import annotations</code> 追加</li><li><code>Dict[str, Any]</code>、<code>Set[str]</code>等の具体的な型アノテーション</li><li><code>Optional[Tuple]</code>等のより明確な引数型</li></ul><h4 id="ドキュメント-3" tabindex="-1">ドキュメント <a class="header-anchor" href="#ドキュメント-3" aria-label="Permalink to &quot;ドキュメント&quot;">​</a></h4><ul><li><code>execute()</code>メソッドにキャッシュ一貫性に関する警告を追加</li><li>docstringの改善（Returns、警告セクション追加）</li></ul><h4 id="バグ修正-8" tabindex="-1">バグ修正 <a class="header-anchor" href="#バグ修正-8" aria-label="Permalink to &quot;バグ修正&quot;">​</a></h4><ul><li>Gitマージコンフリクトの解消（order_by検証の正規表現）</li><li>ReDoS脆弱性の修正（カンマ分割方式に変更）</li></ul><h3 id="_1-0-3rc4-2025-12-09" tabindex="-1">[1.0.3rc4] - 2025-12-09 <a class="header-anchor" href="#_1-0-3rc4-2025-12-09" aria-label="Permalink to &quot;[1.0.3rc4] - 2025-12-09&quot;">​</a></h3><h4 id="追加-5" tabindex="-1">追加 <a class="header-anchor" href="#追加-5" aria-label="Permalink to &quot;追加&quot;">​</a></h4><ul><li><strong>22の新しいSQLiteラッパー関数</strong><ul><li>スキーマ管理: <code>drop_table()</code>, <code>drop_index()</code>, <code>alter_table_add_column()</code>, <code>get_table_schema()</code>, <code>list_indexes()</code></li><li>データ操作: <code>sql_insert()</code>, <code>sql_update()</code>, <code>sql_delete()</code>, <code>upsert()</code>, <code>count()</code>, <code>exists()</code></li><li>クエリ拡張: <code>query_with_pagination()</code> (offset/group_by対応)</li><li>ユーティリティ: <code>vacuum()</code>, <code>get_db_size()</code>, <code>export_table_to_dict()</code>, <code>import_from_dict_list()</code>, <code>get_last_insert_rowid()</code>, <code>pragma()</code></li><li>トランザクション: <code>begin_transaction()</code>, <code>commit()</code>, <code>rollback()</code>, <code>transaction()</code>コンテキストマネージャ</li></ul></li><li>35の新しいテストケース（全て合格）</li><li>完全な後方互換性維持</li></ul><h3 id="_1-0-3rc3-2025-12-09" tabindex="-1">[1.0.3rc3] - 2025-12-09 <a class="header-anchor" href="#_1-0-3rc3-2025-12-09" aria-label="Permalink to &quot;[1.0.3rc3] - 2025-12-09&quot;">​</a></h3><h4 id="追加-6" tabindex="-1">追加 <a class="header-anchor" href="#追加-6" aria-label="Permalink to &quot;追加&quot;">​</a></h4><ul><li><strong>Pydantic互換性</strong><ul><li><code>set_model()</code>, <code>get_model()</code> メソッド</li><li>ネストされたモデルとオプショナルフィールドのサポート</li></ul></li><li><strong>直接SQL実行機能</strong><ul><li><code>execute()</code>, <code>execute_many()</code>, <code>fetch_one()</code>, <code>fetch_all()</code> メソッド</li><li>パラメータバインディングによるSQLインジェクション対策</li></ul></li><li><strong>SQLiteラッパー関数</strong><ul><li><code>create_table()</code>, <code>create_index()</code>, <code>query()</code> メソッド</li><li><code>table_exists()</code>, <code>list_tables()</code> ヘルパー関数</li></ul></li><li>32の新しいテストケース</li><li>英語・日本語ドキュメントの更新</li><li>非同期対応に関する相談文書</li></ul><h3 id="_1-0-0-2025-12-09" tabindex="-1">[1.0.0] - 2025-12-09 <a class="header-anchor" href="#_1-0-0-2025-12-09" aria-label="Permalink to &quot;[1.0.0] - 2025-12-09&quot;">​</a></h3><h4 id="追加-7" tabindex="-1">追加 <a class="header-anchor" href="#追加-7" aria-label="Permalink to &quot;追加&quot;">​</a></h4><ul><li>初回リリース</li><li>dict風インターフェース（<code>db[&quot;key&quot;] = value</code>）</li><li>APSWによるSQLite即時永続化</li><li>遅延ロード（アクセス時にキャッシュ）</li><li>一括ロード（<code>bulk_load=True</code>）</li><li>ネスト構造サポート（30階層テスト済み）</li><li>パフォーマンス最適化（WAL、mmap、cache_size）</li><li>バッチ操作（<code>batch_update</code>、<code>batch_delete</code>）</li><li>コンテキストマネージャ対応</li><li>完全なdictメソッド互換性</li><li>型ヒント（PEP 561）</li><li>バイリンガルドキュメント（英語/日本語）</li><li>GitHub Actions CI（Python 3.9-3.13、Ubuntu/Windows/macOS）</li></ul><hr>',313)])])}const g=o(i,[["render",a]]);export{_ as __pageData,g as default};
